import React from 'react';

class ErrorBoundary extends React.Component {
    constructor(props) {
        super(props);
        this.state = { hasError: false, error: null, errorInfo: null };
    }

    static getDerivedStateFromError(error) {
        return { hasError: true };
    }

    componentDidCatch(error, errorInfo) {
        this.setState({
            error: error,
            errorInfo: errorInfo
        });
        console.error("Uncaught error:", error, errorInfo);
    }

    render() {
        if (this.state.hasError) {
            return (
                <div className="min-h-screen flex items-center justify-center bg-gray-50 p-6">
                    <div className="max-w-xl w-full bg-white rounded-3xl shadow-xl overflow-hidden border border-red-100">
                        <div className="p-8">
                            <div className="w-16 h-16 bg-red-50 rounded-full flex items-center justify-center mb-6 mx-auto">
                                <span className="text-3xl">⚠️</span>
                            </div>
                            <h1 className="text-2xl font-bold text-gray-900 text-center mb-4">Something went wrong</h1>
                            <p className="text-gray-500 text-center mb-8">
                                The application encountered an unexpected error. Please show this to the developer.
                            </p>

                            <div className="bg-gray-900 rounded-xl p-6 overflow-x-auto mb-6">
                                <p className="text-red-400 font-mono text-sm mb-2 font-bold">
                                    {this.state.error && this.state.error.toString()}
                                </p>
                                <pre className="text-gray-400 font-mono text-xs whitespace-pre-wrap">
                                    {this.state.errorInfo && this.state.errorInfo.componentStack}
                                </pre>
                            </div>

                            <div className="flex justify-center">
                                <button
                                    onClick={() => window.location.href = '/'}
                                    className="px-6 py-3 bg-primary text-white font-bold rounded-xl shadow-lg hover:bg-orange-600 transition-all"
                                >
                                    Return to Home
                                </button>
                            </div>
                        </div>
                    </div>
                </div>
            );
        }

        return this.props.children;
    }
}

export default ErrorBoundary;

import { useState, useEffect } from 'react';
import { CreditCard, Wallet, Banknote, Loader, CheckCircle, X } from 'lucide-react';

export default function PaymentModal({ isOpen, onClose, onConfirm, totalAmount }) {
    const [paymentMethod, setPaymentMethod] = useState('online');

    if (!isOpen) return null;

    const handlePay = () => {
        // Pass the method back to parent (cart)
        const method = paymentMethod === 'cash' ? 'cash' : 'online';
        onConfirm(method);
    };

    return (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/50 backdrop-blur-sm animate-fade-in">
            <div className="bg-white rounded-3xl w-full max-w-md shadow-2xl overflow-hidden relative animate-scale-in">
                {/* Header */}
                <div className="bg-gray-50 px-6 py-4 border-b border-gray-100 flex justify-between items-center">
                    <h3 className="font-bold text-lg text-gray-800">
                        Select Payment Method
                    </h3>
                    <button onClick={onClose} className="p-1 hover:bg-gray-200 rounded-full transition-colors">
                        <X className="w-5 h-5 text-gray-500" />
                    </button>
                </div>

                {/* Content */}
                <div className="p-6">
                    <div className="space-y-4">
                        <div className="bg-primary/5 p-4 rounded-xl border border-primary/20 mb-4">
                            <p className="text-sm text-gray-600 mb-1">Total Amount to Pay</p>
                            <p className="text-3xl font-extrabold text-primary">₹{totalAmount}</p>
                        </div>

                        <div className="space-y-3">
                            <PaymentOption
                                id="online"
                                label="Pay Online (Razorpay)"
                                subLabel="UPI, Cards, Netbanking"
                                icons={[
                                    "https://upload.wikimedia.org/wikipedia/commons/f/f2/Google_Pay_Logo.svg",
                                    "https://download.logo.wine/logo/PhonePe/PhonePe-Logo.wine.png",
                                    "https://upload.wikimedia.org/wikipedia/commons/2/24/Paytm_Logo_%28standalone%29.svg",
                                    "https://upload.wikimedia.org/wikipedia/commons/5/5e/Visa_Inc._logo.svg"
                                ]}
                                selected={paymentMethod}
                                onSelect={setPaymentMethod}
                            />
                            <PaymentOption
                                id="cash"
                                label="Cash"
                                subLabel="Pay at Counter"
                                icons={[]}
                                customIcon={<Banknote className="w-6 h-6 text-green-600" />}
                                selected={paymentMethod}
                                onSelect={setPaymentMethod}
                            />
                        </div>

                        {paymentMethod === 'online' && (
                            <div className="mt-4 p-3 bg-gray-50 rounded-xl text-sm text-gray-500 text-center animate-fade-in">
                                You will be redirected to Razorpay secure checkout.
                            </div>
                        )}

                        <button
                            onClick={handlePay}
                            className="w-full mt-4 py-3 bg-primary text-white rounded-xl font-bold hover:bg-primary-hover shadow-lg shadow-primary/30 transition-all active:scale-95 flex items-center justify-center gap-2"
                        >
                            {paymentMethod === 'online' ? 'Proceed to Pay' : 'Confirm Cash Order'} ₹{totalAmount}
                        </button>

                        <div className="text-center mt-4">
                            <p className="text-xs text-gray-400 flex items-center justify-center gap-1">
                                <span className="w-2 h-2 bg-green-500 rounded-full animate-pulse"></span>
                                Secured by Razorpay
                            </p>
                        </div>
                    </div>
                </div>
            </div>
        </div>
    );
}

function PaymentOption({ id, icons, customIcon, label, subLabel, selected, onSelect }) {
    return (
        <label
            className={`
                flex items-center gap-4 p-4 rounded-xl border-2 cursor-pointer transition-all hover:bg-gray-50
                ${selected === id ? 'border-primary bg-primary/5' : 'border-gray-100'}
            `}
            onClick={() => onSelect(id)}
        >
            <div className="flex gap-2">
                {customIcon ? (
                    <div className="w-10 h-10 rounded-full bg-white border border-gray-200 flex items-center justify-center shadow-sm">
                        {customIcon}
                    </div>
                ) : (
                    icons.map((icon, i) => (
                        <div key={i} className="w-10 h-10 rounded-full bg-white border border-gray-200 flex items-center justify-center shadow-sm p-2 overflow-hidden">
                            <img src={icon} alt="" className="w-full h-full object-contain" />
                        </div>
                    ))
                )}
            </div>

            <div className="flex-grow">
                <p className="font-bold text-gray-800">{label}</p>
                <p className="text-xs text-gray-500 font-medium">{subLabel}</p>
            </div>

            <div className={`w-5 h-5 rounded-full border-2 flex items-center justify-center ${selected === id ? 'border-primary' : 'border-gray-300'}`}>
                {selected === id && <div className="w-2.5 h-2.5 bg-primary rounded-full"></div>}
            </div>
        </label>
    );
}

import { createContext, useContext, useState, useEffect } from 'react';
import api from '../api/axios';

const AuthContext = createContext();

export const useAuth = () => useContext(AuthContext);

export const AuthProvider = ({ children }) => {
    const [user, setUser] = useState(null);
    const [loading, setLoading] = useState(true);

    // Load user from local storage on mount
    useEffect(() => {
        const loadUser = async () => {
            const token = localStorage.getItem('token');
            if (!token) {
                setLoading(false);
                return;
            }

            try {
                // Ideally, we should have a /me endpoint to validate token and get user data
                // For now, we'll try to decode from storage or just assume valid if we (later) implement persistence better
                // But specifically for this MVP, let's just keep the user if we have their data in localStorage too
                const storedUser = localStorage.getItem('user');
                if (storedUser) {
                    setUser(JSON.parse(storedUser));
                }
            } catch (error) {
                console.error("Auth Error:", error);
                localStorage.removeItem('token');
                localStorage.removeItem('user');
            } finally {
                setLoading(false);
            }
        };

        loadUser();
    }, []);

    const login = async (email, password) => {
        try {
            const res = await api.post('/auth/login', { email, password });
            const { token, user } = res.data;

            localStorage.setItem('token', token);
            localStorage.setItem('user', JSON.stringify(user));
            setUser(user);
            return { success: true };
        } catch (error) {
            console.error("Login Details:", error.response?.data);
            return {
                success: false,
                message: error.response?.data?.msg || 'Login failed'
            };
        }
    };

    const googleLogin = async (token) => {
        try {
            console.log("Sending Google token to backend:", token.substring(0, 10) + "...");
            const res = await api.post('/auth/google', { token });
            console.log("Backend response:", res.data);
            localStorage.setItem('token', res.data.token);
            localStorage.setItem('user', JSON.stringify(res.data.user));
            setUser(res.data.user);
            return { success: true };
        } catch (error) {
            console.error("Google Login Error in Context:", error.response?.data || error.message);
            return { success: false, message: error.response?.data?.msg || 'Google Login failed' };
        }
    };

    const signup = async (name, email, password) => {
        try {
            const res = await api.post('/auth/signup', { name, email, password });
            // Don't auto-login
            return { success: true };


        } catch (error) {
            console.error("Signup Details:", error.response?.data);
            return {
                success: false,
                message: error.response?.data?.msg || 'Signup failed'
            };
        }
    };

    const logout = () => {
        localStorage.removeItem('token');
        localStorage.removeItem('user');
        setUser(null);
    };

    return (
        <AuthContext.Provider value={{ user, loading, login, googleLogin, signup, logout }}>
            {children}
        </AuthContext.Provider>
    );
};

import { createContext, useContext, useState } from 'react';

const CartContext = createContext();

export function CartProvider({ children }) {
    const [cart, setCart] = useState([]);

    const addToCart = (item) => {
        const itemId = item._id || item.id;
        setCart(prev => {
            const existing = prev.find(i => i.id === itemId);
            if (existing) {
                return prev.map(i => i.id === itemId ? { ...i, quantity: i.quantity + 1 } : i);
            }
            return [...prev, { ...item, id: itemId, quantity: 1 }];
        });
    };

    const addMultipleToCart = (items) => {
        setCart(prev => {
            const newCart = [...prev];
            items.forEach(item => {
                const itemId = item._id || item.id;
                const newItem = { ...item, id: itemId };
                const existingIndex = newCart.findIndex(i => i.id === itemId);
                if (existingIndex > -1) {
                    newCart[existingIndex].quantity += newItem.quantity;
                } else {
                    newCart.push(newItem);
                }
            });
            return newCart;
        });
    };

    const removeFromCart = (id) => {
        setCart(prev => prev.filter(i => i.id !== id));
    };

    const updateQuantity = (id, delta) => {
        setCart(prev => prev.map(i => {
            if (i.id === id) {
                const newQty = Math.max(0, i.quantity + delta);
                return { ...i, quantity: newQty };
            }
            return i;
        }).filter(i => i.quantity > 0));
    };

    const clearCart = () => setCart([]);

    const totalAmount = cart.reduce((sum, item) => sum + (item.price * item.quantity), 0);
    const totalItems = cart.reduce((sum, item) => sum + item.quantity, 0);

    return (
        <CartContext.Provider value={{ cart, addToCart, addMultipleToCart, removeFromCart, updateQuantity, clearCart, totalAmount, totalItems }}>
            {children}
        </CartContext.Provider>
    );
}

export const useCart = () => useContext(CartContext);

import { useState, useEffect } from 'react';
import { useCart } from '../context/CartContext';
import { useAuth } from '../context/AuthContext';
import { Trash2, ArrowLeft, CheckCircle, Loader, AlertCircle, ShoppingBag, Plus, Minus, Ticket, FileText, Clock, ArrowRight, X } from 'lucide-react';
import TimeSlotPicker from '../components/TimeSlotPicker';
import PaymentModal from '../components/PaymentModal';
import { Link, useNavigate } from 'react-router-dom';
import api from '../api/axios';
import confetti from 'canvas-confetti';
import toast from 'react-hot-toast';

export default function CartPage() {
    const { cart, removeFromCart, updateQuantity, totalAmount, clearCart, totalItems } = useCart();
    const { user } = useAuth();
    const navigate = useNavigate();

    const [selectedSlot, setSelectedSlot] = useState(null);
    const [loading, setLoading] = useState(false);
    const [error, setError] = useState(null);
    const [orderPlaced, setOrderPlaced] = useState(null);
    const [isPaymentModalOpen, setIsPaymentModalOpen] = useState(false);
    const [instructions, setInstructions] = useState('');
    const [couponCode, setCouponCode] = useState('');
    const [taxPercentage, setTaxPercentage] = useState(5);

    useEffect(() => {
        const fetchSettings = async () => {
            try {
                const res = await api.get('/admin/settings');
                if (res.data.success && res.data.settings) {
                    setTaxPercentage(res.data.settings.taxPercentage || 0);
                }
            } catch (err) {
                console.error("Failed to load settings:", err);
            }
        };
        fetchSettings();
    }, []);

    const handleUpdateQuantity = (id, delta, currentQty) => {
        const newQty = currentQty + delta;
        if (newQty < 1) return; // Minimum 1
        if (newQty > 10) return; // Maximum 10
        updateQuantity(id, delta);
    };

    const handleRemoveItem = (id) => {
        if (window.confirm("Are you sure you want to remove this item?")) {
            removeFromCart(id);
        }
    };

    const handleProceedToPay = () => {
        if (!selectedSlot) return;
        if (!user) {
            navigate('/login');
            return;
        }
        setIsPaymentModalOpen(true);
    };

    const loadRazorpayScript = () => {
        return new Promise((resolve) => {
            const script = document.createElement('script');
            script.src = 'https://checkout.razorpay.com/v1/checkout.js';
            script.onload = () => resolve(true);
            script.onerror = () => resolve(false);
            document.body.appendChild(script);
        });
    };

    const handleConfirmPayment = async (method) => {
        setIsPaymentModalOpen(false);
        setLoading(true);
        setError(null);

        if (method === 'cash') {
            // Cash Order logic (existing /orders route)
            try {
                const orderData = {
                    user: user.id,
                    items: cart.map(item => ({
                        foodItem: item.id,
                        name: item.name,
                        price: item.price,
                        quantity: item.quantity
                    })),
                    totalAmount: totalAmount + Math.round(totalAmount * (taxPercentage / 100)),
                    pickupSlot: selectedSlot,
                    instructions: instructions
                };

                const res = await api.post('/orders', orderData);
                const newOrder = res.data;
                handleOrderSuccess(newOrder);

            } catch (err) {
                console.error("Order Error:", err);
                setError(err.response?.data?.msg || "Failed to place order.");
                toast.error("Failed to place order. Please try again.");
                setLoading(false);
            }
        } else {
            // Razorpay logic
            await handleRazorpayPayment();
        }
    };

    const handleRazorpayPayment = async () => {
        const res = await loadRazorpayScript();

        if (!res) {
            alert('Razorpay SDK failed to load. Are you online?');
            setLoading(false);
            return;
        }

        try {
            // 1. Create Order
            const amount = totalAmount + Math.round(totalAmount * (taxPercentage / 100));
            const result = await api.post('/payment/create-order', { amount });

            if (!result) {
                alert("Server error. Are you online?");
                toast.error("Server error. Please check your connection.");
                setLoading(false);
                return;
            }

            const { amount: orderAmount, id: order_id, currency } = result.data;

            // 2. Open Razorpay
            const options = {
                key: import.meta.env.VITE_RAZORPAY_KEY_ID,
                amount: orderAmount.toString(),
                currency: currency,
                name: "QuickBite Canteen",
                description: "Campus Food Order",
                order_id: order_id,
                handler: async function (response) {
                    // 3. Verify Payment
                    try {
                        const orderData = {
                            items: cart.map(item => ({
                                foodItem: item.id,
                                name: item.name,
                                price: item.price,
                                quantity: item.quantity
                            })),
                            totalAmount: amount,
                            pickupSlot: selectedSlot,
                            instructions: instructions
                        };

                        const verifyRes = await api.post('/payment/verify', {
                            razorpay_order_id: response.razorpay_order_id,
                            razorpay_payment_id: response.razorpay_payment_id,
                            razorpay_signature: response.razorpay_signature,
                            orderData
                        });

                        if (verifyRes.data.success) {
                            handleOrderSuccess(verifyRes.data.order);
                        } else {
                            toast.error("Payment verification failed");
                            setLoading(false);
                        }
                    } catch (err) {
                        console.error("Verification Error:", err);
                        toast.error("Payment verification failed");
                        setLoading(false);
                    }
                },
                prefill: {
                    name: user.name,
                    email: user.email,
                    contact: "9999999999" // Dummy or from user profile
                },
                notes: {
                    address: "Campus Canteen"
                },
                theme: {
                    color: "#F97316" // Primary Orange
                },
                modal: {
                    ondismiss: function () {
                        setLoading(false);
                        // alert('Payment cancelled'); // Optional: notify user
                    }
                }
            };

            const paymentObject = new window.Razorpay(options);
            paymentObject.open();
            paymentObject.on('payment.failed', function (response) {
                toast.error(response.error.description);
                setLoading(false);
            });

        } catch (err) {
            console.error("Razorpay Error:", err);
            setError("Payment failed. Please try again.");
            toast.error("Payment initialization failed.");
            setLoading(false);
        }
    };

    const handleOrderSuccess = (newOrder) => {
        setOrderPlaced({
            token: newOrder.tokenNumber,
            slot: newOrder.pickupSlot,
            items: cart,
            total: newOrder.totalAmount
        });
        clearCart();
        confetti({
            particleCount: 100,
            spread: 70,
            origin: { y: 0.6 }
        });
        toast.success("Order placed successfully! 🎉");
        setLoading(false);
    };

    if (orderPlaced) {
        return (
            <div className="min-h-screen bg-slate-50 flex flex-col items-center justify-center p-4">
                <div className="bg-white p-8 rounded-2xl shadow-xl max-w-md w-full text-center space-y-6 animate-fade-in-up">
                    <div className="w-20 h-20 bg-green-100 rounded-full flex items-center justify-center mx-auto">
                        <CheckCircle className="w-10 h-10 text-green-600" />
                    </div>
                    <h2 className="text-3xl font-bold text-gray-800">Order Confirmed!</h2>
                    <div className="bg-orange-50 p-6 rounded-xl border border-orange-100">
                        <p className="text-gray-500 text-sm uppercase tracking-wide mb-1">Your Token Number</p>
                        <p className="text-5xl font-extrabold text-primary">{orderPlaced.token}</p>
                    </div>
                    <div className="text-left space-y-2 text-gray-600 bg-gray-50 p-4 rounded-lg">
                        <div className="flex justify-between">
                            <span>Pickup Time:</span>
                            <span className="font-bold text-gray-800">{orderPlaced.slot}</span>
                        </div>
                        <div className="flex justify-between">
                            <span>Total Amount:</span>
                            <span className="font-bold text-gray-800">₹{orderPlaced.total}</span>
                        </div>
                    </div>
                    <Link to="/orders" className="block w-full bg-primary text-white py-3 rounded-xl font-bold shadow-lg hover:bg-orange-600 transition-colors">
                        View My Orders
                    </Link>
                    <Link to="/" className="block w-full text-center text-gray-500 font-medium hover:text-primary mt-2">
                        Back to Home
                    </Link>
                </div>
            </div>
        );
    }

    return (
        <div className="max-w-7xl mx-auto px-4 py-8 sm:px-6 lg:px-8 bg-gray-50 min-h-screen">
            {/* Header */}
            <div className="flex items-center gap-4 mb-8">
                <Link to="/menu" className="p-2 hover:bg-gray-200 rounded-full transition-colors bg-white shadow-sm">
                    <ArrowLeft className="w-6 h-6 text-gray-600" />
                </Link>
                <div className="flex-1">
                    <h1 className="text-3xl font-bold text-gray-800">🛒 Your Cart</h1>
                    <p className="text-gray-500 text-sm">Review your order before checkout</p>
                </div>
            </div>

            {error && (
                <div className="bg-red-50 border-l-4 border-red-500 p-4 mb-6 rounded-r-lg flex items-center gap-3 animate-shake">
                    <AlertCircle className="w-5 h-5 text-red-500" />
                    <p className="text-red-700 text-sm font-medium">{error}</p>
                </div>
            )}

            {cart.length === 0 ? (
                <div className="text-center py-24 bg-white rounded-3xl shadow-sm border border-gray-200 animate-fade-in-up">
                    <div className="bg-orange-50 w-24 h-24 rounded-full flex items-center justify-center mx-auto mb-6">
                        <ShoppingBag className="w-12 h-12 text-primary/40" />
                    </div>
                    <h2 className="text-2xl font-bold text-gray-900 mb-2">Your cart is empty</h2>
                    <p className="text-gray-500 mb-8 max-w-sm mx-auto">Looks like you haven't added any delicious meals yet.</p>
                    <Link to="/menu" className="inline-flex items-center gap-2 px-8 py-4 bg-primary text-white rounded-full font-bold text-lg shadow-lg hover:bg-orange-600 hover:scale-105 transition-all">
                        👉 Browse Menu
                    </Link>
                </div>
            ) : (
                <div className="grid lg:grid-cols-12 gap-8 items-start">

                    {/* LEFT SIDE (70%) */}
                    <div className="lg:col-span-8 space-y-6">

                        {/* Cart Items List (Card Layout) */}
                        <div className="space-y-4">
                            {cart.map((item, index) => (
                                <div key={item.id} className="bg-white rounded-2xl p-4 shadow-sm border border-gray-100 flex flex-col sm:flex-row items-center gap-6 animate-slide-up hover:shadow-md transition-shadow relative group">

                                    {/* Image */}
                                    <div className="w-24 h-24 flex-shrink-0 rounded-xl overflow-hidden bg-gray-100 border border-gray-200">
                                        <img src={item.image} alt={item.name} className="w-full h-full object-cover" />
                                    </div>

                                    {/* Info */}
                                    <div className="flex-1 text-center sm:text-left space-y-1">
                                        <h3 className="font-bold text-lg text-gray-800">{item.name}</h3>
                                        <p className="text-gray-500 font-medium">₹{item.price}</p>
                                    </div>

                                    {/* Quantity Controls */}
                                    <div className="flex flex-col items-center gap-2">
                                        <div className="inline-flex items-center bg-gray-50 rounded-lg border border-gray-200 p-1">
                                            <button
                                                onClick={() => handleUpdateQuantity(item.id, -1, item.quantity)}
                                                disabled={item.quantity <= 1}
                                                className={`w-8 h-8 flex items-center justify-center rounded-md transition-all font-bold ${item.quantity <= 1 ? 'text-gray-300 cursor-not-allowed' : 'text-gray-600 hover:bg-white hover:shadow-sm'}`}
                                            >
                                                <Minus className="w-4 h-4" />
                                            </button>
                                            <span className="w-10 text-center font-bold text-gray-800">{item.quantity}</span>
                                            <button
                                                onClick={() => handleUpdateQuantity(item.id, 1, item.quantity)}
                                                disabled={item.quantity >= 10}
                                                className={`w-8 h-8 flex items-center justify-center rounded-md transition-all font-bold ${item.quantity >= 10 ? 'text-gray-300 cursor-not-allowed' : 'text-primary hover:bg-white hover:shadow-sm'}`}
                                            >
                                                <Plus className="w-4 h-4" />
                                            </button>
                                        </div>
                                        <p className="text-xs text-gray-400 font-medium">Max 10</p>
                                    </div>

                                    {/* Subtotal */}
                                    <div className="text-right min-w-[80px]">
                                        <p className="text-xs text-gray-500 mb-1">Subtotal</p>
                                        <p className="font-bold text-xl text-primary">₹{item.price * item.quantity}</p>
                                    </div>

                                    {/* Remove Button */}
                                    <button
                                        onClick={() => handleRemoveItem(item.id)}
                                        className="sm:static absolute top-2 right-2 p-2 text-red-500 hover:bg-red-50 rounded-full transition-colors"
                                        title="Remove Item"
                                    >
                                        <X className="w-5 h-5" />
                                    </button>
                                </div>
                            ))}
                        </div>

                        {/* Clear Cart Button */}
                        {cart.length > 0 && (
                            <div className="flex justify-end">
