import { useState, useEffect, useRef } from 'react';
import FoodCard from '../components/FoodCard';
import { useCart } from '../context/CartContext';
import { ShoppingCart, Search, Filter, X, ChevronRight, ChevronLeft, Sparkles, Loader, Leaf, Drumstick } from 'lucide-react';
import { Link } from 'react-router-dom';
import api from '../api/axios';

const CATEGORIES = ['All', 'Snacks', 'Lunch', 'South Indian', 'Beverages', 'Chinese', 'Continental', 'Desserts'];

export default function MenuPage() {
    const [selectedCategory, setSelectedCategory] = useState('All');
    const [searchQuery, setSearchQuery] = useState('');
    const [onlyVeg, setOnlyVeg] = useState(false);
    const [onlyNonVeg, setOnlyNonVeg] = useState(false);
    const [showFilters, setShowFilters] = useState(false);
    const [sortBy, setSortBy] = useState('recommended');
    const [priceRange, setPriceRange] = useState('all');
    const [currentPage, setCurrentPage] = useState(1);
    const itemsPerPage = 12;
    const [menuItems, setMenuItems] = useState([]);
    const [loading, setLoading] = useState(true);
    const [error, setError] = useState(null);
    const { totalItems, totalAmount, addToCart } = useCart();

    const categoryScrollRef = useRef(null);

    useEffect(() => {
        const fetchMenu = async () => {
            try {
                const res = await api.get('/menu/all');
                setMenuItems(res.data);
                setLoading(false);
            } catch (err) {
                console.error("Failed to fetch menu:", err);
                setError("Failed to load menu. Please make sure server is running.");
                setLoading(false);
            }
        };
        fetchMenu();
    }, []);

    const filteredItems = menuItems.filter(item => {
        const matchesCategory = selectedCategory === 'All' || item.category === selectedCategory;
        const matchesSearch = item.name.toLowerCase().includes(searchQuery.toLowerCase());
        const matchesVeg = !onlyVeg || item.isVeg;
        const matchesNonVeg = !onlyNonVeg || !item.isVeg;

        // Price Filter
        let matchesPrice = true;
        if (priceRange === 'under100') matchesPrice = item.price < 100;
        else if (priceRange === '100to200') matchesPrice = item.price >= 100 && item.price <= 200;
        else if (priceRange === 'above200') matchesPrice = item.price > 200;

        return matchesCategory && matchesSearch && matchesVeg && matchesNonVeg && matchesPrice;
    }).sort((a, b) => {
        if (sortBy === 'priceLow') return a.price - b.price;
        if (sortBy === 'priceHigh') return b.price - a.price;
        return 0; // recommended (default order)
    });

    // Pagination Logic
    const totalPages = Math.ceil(filteredItems.length / itemsPerPage);
    const currentItems = filteredItems.slice(
        (currentPage - 1) * itemsPerPage,
        currentPage * itemsPerPage
    );

    // Reset to first page when filters change
    useEffect(() => {
        setCurrentPage(1);
    }, [selectedCategory, searchQuery, onlyVeg, onlyNonVeg, sortBy, priceRange]);

    // Scroll to top when page changes
    useEffect(() => {
        window.scrollTo({ top: 0, behavior: 'smooth' });
    }, [currentPage]);

    const renderPaginationButtons = () => {
        const pages = [];
        if (totalPages <= 7) {
            for (let i = 1; i <= totalPages; i++) pages.push(i);
        } else {
            if (currentPage <= 4) {
                pages.push(1, 2, 3, 4, 5, '...', totalPages);
            } else if (currentPage >= totalPages - 3) {
                pages.push(1, '...', totalPages - 4, totalPages - 3, totalPages - 2, totalPages - 1, totalPages);
            } else {
                pages.push(1, '...', currentPage - 1, currentPage, currentPage + 1, '...', totalPages);
            }
        }

        return pages.map((page, index) => (
            page === '...' ? (
                <span key={`ellipsis-${index}`} className="w-10 h-10 flex items-center justify-center text-gray-400">...</span>
            ) : (
                <button
                    key={page}
                    onClick={() => setCurrentPage(page)}
                    className={`w-10 h-10 rounded-xl font-bold text-sm transition-all ${currentPage === page
                        ? 'bg-primary text-white shadow-lg shadow-primary/25'
                        : 'text-gray-600 hover:bg-gray-50'
                        }`}
                >
                    {page}
                </button>
            )
        ));
    };

    const scrollCategories = (direction) => {
        if (categoryScrollRef.current) {
            const scrollAmount = 200;
            categoryScrollRef.current.scrollBy({
                left: direction === 'left' ? -scrollAmount : scrollAmount,
                behavior: 'smooth'
            });
        }
    };

    return (
        <div className="min-h-screen bg-gray-50/50 pb-32 font-sans">
            {/* Sticky Header */}
            <div className="bg-white/80 backdrop-blur-md sticky top-0 z-50 border-b border-gray-100 shadow-sm transition-all duration-300">
                <div className="max-w-7xl mx-auto px-4 py-4">
                    {/* Top Row: Title & Cart */}
                    <div className="flex items-center justify-between mb-4">
                        <div className="flex items-center gap-2">
                            <div className="bg-primary/10 p-2 rounded-xl">
                                <Sparkles className="w-6 h-6 text-primary" />
                            </div>
                            <div>
                                <h1 className="text-2xl font-black text-gray-900 tracking-tight">Our Menu</h1>
                                <p className="text-xs text-gray-500 font-bold uppercase tracking-wider">{filteredItems.length} items</p>
                            </div>
                        </div>


                    </div>

                    {/* Middle Row: Search & Veg Toggle */}
                    <div className="flex flex-col sm:flex-row gap-3">
                        <div className="relative flex-grow group">
                            <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-gray-400 w-5 h-5 group-focus-within:text-primary transition-colors" />
                            <input
                                type="text"
                                placeholder="Search for food..."
                                value={searchQuery}
                                onChange={(e) => setSearchQuery(e.target.value)}
                                className="w-full pl-12 pr-10 py-3 bg-gray-100/50 border-none rounded-2xl focus:bg-white focus:ring-2 focus:ring-primary/20 transition-all font-medium placeholder:text-gray-400"
                            />
                            {searchQuery && (
                                <button
                                    onClick={() => setSearchQuery('')}
                                    className="absolute right-3 top-1/2 -translate-y-1/2 text-gray-400 hover:text-gray-600 bg-gray-200/50 rounded-full p-1"
                                >
                                    <X className="w-4 h-4" />
                                </button>
                            )}
                        </div>

                        <button
                            onClick={() => {
                                setOnlyVeg(!onlyVeg);
                                if (!onlyVeg) setOnlyNonVeg(false);
                            }}
                            className={`flex items-center gap-2 px-4 py-2.5 rounded-2xl border transition-all duration-300 group ${onlyVeg
                                ? 'bg-green-50 border-green-500 text-green-700 shadow-md shadow-green-100'
                                : 'bg-white border-gray-200 text-gray-500 hover:border-green-200 hover:text-green-600 hover:shadow-sm'
                                }`}
                        >
                            <div className={`p-1.5 rounded-full transition-colors ${onlyVeg ? 'bg-green-500 text-white' : 'bg-gray-100 text-gray-400 group-hover:bg-green-100 group-hover:text-green-500'}`}>
                                <Leaf className="w-4 h-4 fill-current" />
                            </div>
                            <span className="font-bold text-sm">Veg Only</span>
                        </button>

                        <button
                            onClick={() => {
                                setOnlyNonVeg(!onlyNonVeg);
                                if (!onlyNonVeg) setOnlyVeg(false);
                            }}
                            className={`flex items-center gap-2 px-4 py-2.5 rounded-2xl border transition-all duration-300 group ${onlyNonVeg
                                ? 'bg-red-50 border-red-500 text-red-700 shadow-md shadow-red-100'
                                : 'bg-white border-gray-200 text-gray-500 hover:border-red-200 hover:text-red-600 hover:shadow-sm'
                                }`}
                        >
                            <div className={`p-1.5 rounded-full transition-colors ${onlyNonVeg ? 'bg-red-500 text-white' : 'bg-gray-100 text-gray-400 group-hover:bg-red-100 group-hover:text-red-500'}`}>
                                <Drumstick className="w-4 h-4 fill-current" />
                            </div>
                            <span className="font-bold text-sm">Non-Veg Only</span>
                        </button>


                    </div>

                    {/* Bottom Row: Categories (Horizontal Scroll) */}
                    <div className="relative mt-4 -mx-4 px-4 sm:mx-0 sm:px-0">
                        <div className="absolute left-0 top-0 bottom-0 w-8 bg-gradient-to-r from-white to-transparent z-10 pointer-events-none sm:hidden" />
                        <div className="absolute right-0 top-0 bottom-0 w-8 bg-gradient-to-l from-white to-transparent z-10 pointer-events-none sm:hidden" />

                        <div
                            ref={categoryScrollRef}
                            className="flex gap-3 overflow-x-auto pb-2 scrollbar-none snap-x"
                            style={{ scrollbarWidth: 'none', msOverflowStyle: 'none' }}
                        >
                            {CATEGORIES.map((cat, idx) => (
                                <button
                                    key={cat}
                                    onClick={() => setSelectedCategory(cat)}
                                    className={`
                                        snap-start shrink-0 px-5 py-2 rounded-full font-bold text-sm transition-all
                                        ${selectedCategory === cat
                                            ? 'bg-primary text-white shadow-lg shadow-primary/25 scale-105'
                                            : 'bg-white text-gray-500 border border-gray-100 hover:bg-gray-50 hover:border-gray-200'}
                                    `}
                                >
                                    {cat}
                                </button>
                            ))}

                            {/* Filter Button */}
                            <button
                                onClick={() => setShowFilters(!showFilters)}
                                className={`
                                        snap-start shrink-0 px-5 py-2 rounded-full font-bold text-sm transition-all flex items-center gap-2
                                        ${showFilters || sortBy !== 'recommended' || priceRange !== 'all'
                                        ? 'bg-primary text-white shadow-lg shadow-primary/25 scale-105'
                                        : 'bg-white text-gray-500 border border-gray-100 hover:bg-gray-50 hover:border-gray-200'}
                                    `}
                            >
                                <Filter className="w-4 h-4" />
                                <span>Filters</span>
                                {(sortBy !== 'recommended' || priceRange !== 'all') && (
                                    <span className="bg-white text-primary text-[10px] rounded-full w-4 h-4 flex items-center justify-center font-bold">
                                        {(sortBy !== 'recommended' ? 1 : 0) + (priceRange !== 'all' ? 1 : 0)}
                                    </span>
                                )}
                            </button>
                        </div>
                    </div>

                    {/* Filter Modal (Fixed Position) */}
                    {showFilters && (
                        <>
                            <div className="fixed inset-0 z-[60] bg-black/20 backdrop-blur-sm" onClick={() => setShowFilters(false)}></div>
                            <div className="fixed left-1/2 top-1/2 -translate-x-1/2 -translate-y-1/2 w-[90%] max-w-sm bg-white rounded-3xl shadow-2xl border border-gray-100 p-6 z-[70] animate-scale-up">
                                <div className="flex items-center justify-between mb-6">
                                    <h2 className="text-xl font-black text-gray-900">Filters</h2>
                                    <button onClick={() => setShowFilters(false)} className="p-2 hover:bg-gray-100 rounded-full transition-colors">
                                        <X className="w-5 h-5 text-gray-500" />
                                    </button>
                                </div>

                                <div className="space-y-6">
                                    {/* Sort Section */}
                                    <div>
                                        <h3 className="text-xs font-bold text-gray-400 uppercase tracking-wider mb-3">Sort By</h3>
                                        <div className="space-y-2">
                                            {[
                                                { label: 'Recommended', value: 'recommended' },
                                                { label: 'Price: Low to High', value: 'priceLow' },
                                                { label: 'Price: High to Low', value: 'priceHigh' },
                                            ].map((option) => (
                                                <label key={option.value} className="flex items-center justify-between cursor-pointer group p-2 hover:bg-gray-50 rounded-xl transition-colors">
                                                    <span className={`text-sm font-medium transition-colors ${sortBy === option.value ? 'text-primary' : 'text-gray-600 group-hover:text-gray-900'}`}>{option.label}</span>
                                                    <input
                                                        type="radio"
                                                        name="sort"
                                                        className="accent-primary w-4 h-4"
                                                        checked={sortBy === option.value}
                                                        onChange={() => setSortBy(option.value)}
                                                    />
                                                </label>
                                            ))}
                                        </div>
                                    </div>

                                    <div className="h-px bg-gray-100"></div>

                                    {/* Price Range Section */}
                                    <div>
                                        <h3 className="text-xs font-bold text-gray-400 uppercase tracking-wider mb-3">Price Range</h3>
                                        <div className="flex flex-wrap gap-2">
                                            {[
                                                { label: 'Any', value: 'all' },
                                                { label: 'Under ₹100', value: 'under100' },
                                                { label: '₹100 - ₹200', value: '100to200' },
                                                { label: 'Above ₹200', value: 'above200' },
                                            ].map((range) => (
                                                <button
                                                    key={range.value}
                                                    onClick={() => setPriceRange(range.value)}
                                                    className={`px-3 py-1.5 rounded-lg text-xs font-bold border transition-all ${priceRange === range.value
                                                        ? 'bg-primary text-white border-primary'
                                                        : 'bg-white text-gray-600 border-gray-200 hover:border-gray-300'
                                                        }`}
                                                >
                                                    {range.label}
                                                </button>
                                            ))}
                                        </div>
                                    </div>

                                    {/* Actions */}
                                    <div className="flex gap-3 pt-2">
                                        {(sortBy !== 'recommended' || priceRange !== 'all') && (
                                            <button
                                                onClick={() => { setSortBy('recommended'); setPriceRange('all'); }}
                                                className="flex-1 py-3 text-sm text-red-500 font-bold bg-red-50 hover:bg-red-100 rounded-xl transition-colors"
                                            >
                                                Clear
                                            </button>
                                        )}
                                        <button
                                            onClick={() => setShowFilters(false)}
                                            className="flex-1 py-3 text-sm text-white font-bold bg-primary hover:bg-primary-hover rounded-xl shadow-lg shadow-primary/25 transition-all active:scale-95"
                                        >
                                            Apply Filters
                                        </button>
                                    </div>
                                </div>
                            </div>
                        </>
                    )}
                </div>
            </div>

            {/* Content */}
            <div className="max-w-7xl mx-auto px-4 py-8">
                {loading ? (
                    <div className="text-center py-20">
                        <Loader className="w-10 h-10 text-primary animate-spin mx-auto mb-4" />
                        <p className="text-gray-500 font-medium">Loading delicious items...</p>
                    </div>
                ) : error ? (
                    <div className="text-center py-20 bg-red-50 rounded-3xl">
                        <p className="text-red-500 font-bold">{error}</p>
                    </div>
                ) : filteredItems.length === 0 ? (
                    <div className="text-center py-32 bg-white rounded-3xl border border-gray-100 border-dashed">
                        <Search className="w-16 h-16 text-gray-200 mx-auto mb-4" />
                        <h3 className="text-xl font-bold text-gray-900">No items found</h3>
                        <p className="text-gray-500 mt-2">Try adjusting your filters</p>
                        <button
                            onClick={() => { setSelectedCategory('All'); setSearchQuery(''); setOnlyVeg(false); setOnlyNonVeg(false); setSortBy('recommended'); setPriceRange('all'); }}
                            className="mt-6 text-primary font-bold hover:underline"
                        >
                            Clear all filters
                        </button>
                    </div>
                ) : (
                    <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-6 sm:gap-8">
                        {currentItems.map((item, index) => (
                            <FoodCard key={item._id} item={item} onAdd={addToCart} index={index} />
                        ))}
                    </div>
                )}

                {/* Pagination Controls */}
                {!loading && !error && filteredItems.length > 0 && totalPages > 1 && (
                    <div className="flex justify-center mt-12">
                        <div className="flex bg-white rounded-2xl shadow-sm border border-gray-100 p-2 gap-1 sm:gap-2">
                            <button
                                onClick={() => setCurrentPage(prev => Math.max(prev - 1, 1))}
                                disabled={currentPage === 1}
                                className="w-10 h-10 flex items-center justify-center rounded-xl hover:bg-gray-50 disabled:opacity-30 disabled:cursor-not-allowed transition-colors text-gray-600"
                            >
                                <ChevronLeft className="w-5 h-5" />
                            </button>

                            {renderPaginationButtons()}

                            <button
                                onClick={() => setCurrentPage(prev => Math.min(prev + 1, totalPages))}
                                disabled={currentPage === totalPages}
                                className="w-10 h-10 flex items-center justify-center rounded-xl hover:bg-gray-50 disabled:opacity-30 disabled:cursor-not-allowed transition-colors text-gray-600"
                            >
                                <ChevronRight className="w-5 h-5" />
                            </button>
                        </div>
                    </div>
                )}
            </div>
            {/* Floating Cart Bar */}
            {totalItems > 0 && (
                <div className="fixed bottom-6 left-4 right-4 z-50 animate-slide-up">
                    <Link to="/cart" className="bg-primary text-white p-3 rounded-2xl shadow-xl shadow-primary/20 flex items-center justify-between hover:bg-primary-hover transition-all group border border-white/20 backdrop-blur-xl max-w-xl mx-auto">
                        <div className="flex items-center gap-3">
                            <div className="bg-white/20 p-2 rounded-xl backdrop-blur-sm">
                                <ShoppingCart className="w-5 h-5 text-white group-hover:scale-110 transition-transform" />
                            </div>
                            <div className="flex flex-col">
                                <span className="font-bold text-[10px] text-white/80 uppercase tracking-wider leading-none mb-0.5">{totalItems} ITEMS</span>
                                <span className="font-black text-lg text-white leading-none">₹{totalAmount}</span>
                            </div>
                        </div>

                        <div className="flex items-center gap-1.5 font-bold bg-white text-primary px-4 py-2 rounded-xl shadow-sm group-hover:bg-white/90 transition-colors text-sm">
                            View Cart
                            <ChevronRight className="w-4 h-4" />
                        </div>
                    </Link>
                </div>
            )}
        </div>
    );
}

import { useState, useEffect } from 'react';
import api from '../api/axios';
import { useCart } from '../context/CartContext';
import {
    Clock, CheckCircle, Utensils, AlertCircle, Loader, ChefHat,
    Package, ShoppingBag, Search, XCircle, RotateCcw, Filter, ChevronRight
} from 'lucide-react';
import { Link } from 'react-router-dom';
import toast from 'react-hot-toast';
import { io } from 'socket.io-client';
import PostOrderCompletion from '../components/PostOrderCompletion';

export default function OrdersPage() {
    const [orders, setOrders] = useState([]);
    const [filteredOrders, setFilteredOrders] = useState([]);
    const [loading, setLoading] = useState(true);
    const [error, setError] = useState(null);
    const [searchTerm, setSearchTerm] = useState('');
    const [activeFilter, setActiveFilter] = useState('All');

    // Derived state for stats
    const totalOrders = orders.length;
    const activeOrders = orders.filter(o => ['Pending', 'Preparing', 'Ready'].includes(o.status)).length;

    useEffect(() => {
        const fetchOrders = async () => {
            try {
                const res = await api.get('/orders/my-orders');
                setOrders(res.data);
                setFilteredOrders(res.data);
            } catch (err) {
                console.error("Fetch Orders Error:", err);
                setError("Failed to load your orders.");
            } finally {
                setLoading(false);
            }
        };

        fetchOrders();
    }, []);

    // Socket.io Real-time Updates
    useEffect(() => {
        const socket = io('http://localhost:5000');

        socket.on('connect', () => {
            console.log('Connected to real-time updates');
        });

        socket.on('orderStatusUpdated', (updatedOrder) => {
            // Check if the order belongs to this user's list
            setOrders(prevOrders => {
                const orderExists = prevOrders.some(o => o._id === updatedOrder._id);
                if (orderExists) {
                    toast.success(`Order #${updatedOrder._id.slice(-6).toUpperCase()} is now ${updatedOrder.status}!`, {
                        icon: '🔔',
                    });
                    return prevOrders.map(o => o._id === updatedOrder._id ? { ...o, status: updatedOrder.status } : o);
                }
                return prevOrders;
            });
        });

        return () => {
            socket.disconnect();
        };
    }, []);

    // Filter Logic
    useEffect(() => {
        let result = orders;

        // 1. Search Filter
        if (searchTerm) {
            const term = searchTerm.toLowerCase();
            result = result.filter(order =>
                order.tokenNumber.toLowerCase().includes(term) ||
                order._id.toLowerCase().includes(term)
            );
        }

        // 2. Category Filter
        const now = new Date();
        const startOfDay = new Date(now.getFullYear(), now.getMonth(), now.getDate());
        const startOfWeek = new Date(now.setDate(now.getDate() - now.getDay()));
        const startOfMonth = new Date(now.getFullYear(), now.getMonth(), 1);

        switch (activeFilter) {
            case 'Today':
                result = result.filter(o => new Date(o.createdAt) >= startOfDay);
                break;
            case 'This Week':
                result = result.filter(o => new Date(o.createdAt) >= startOfWeek);
                break;
            case 'This Month':
                result = result.filter(o => new Date(o.createdAt) >= startOfMonth);
                break;
            case 'Pending':
                result = result.filter(o => ['Pending', 'Preparing'].includes(o.status));
                break;
            default:
                break;
        }

        setFilteredOrders(result);
    }, [searchTerm, activeFilter, orders]);

    const handleOrderUpdate = (updatedOrder) => {
        setOrders(prev => prev.map(o => o._id === updatedOrder._id ? updatedOrder : o));
    };

    if (loading) {
        return (
            <div className="min-h-screen flex items-center justify-center">
                <Loader className="w-10 h-10 text-primary animate-spin" />
            </div>
        );
    }

    return (
        <div className="max-w-5xl mx-auto px-4 py-8 sm:px-6 lg:px-8 bg-gray-50/50 min-h-screen font-sans">
            {/* Header Section */}
            <div className="flex flex-col md:flex-row md:items-end justify-between mb-8 gap-4 animate-fade-in">
                <div>
                    <h1 className="text-3xl font-black text-gray-900 tracking-tight">My Orders</h1>
                    <p className="text-gray-500 mt-1 font-medium">
                        You have <span className="text-primary font-bold">{activeOrders} active</span> orders
                    </p>
                </div>
                <Link to="/menu" className="inline-flex items-center gap-2 px-6 py-3 bg-gray-900 text-white rounded-xl font-bold hover:bg-black transition-all shadow-lg hover:translate-y-[-2px]">
                    <Utensils className="w-5 h-5" />
                    Order New Meal
                </Link>
            </div>

            {error && (
                <div className="bg-red-50 border-l-4 border-red-500 p-4 rounded-r-xl mb-8 flex items-center gap-3 animate-shake">
                    <AlertCircle className="w-6 h-6 text-red-500" />
                    <p className="text-red-700 font-medium">{error}</p>
                </div>
            )}

            {/* Filters & Search Bar */}
            <div className="bg-white p-4 rounded-2xl shadow-sm border border-gray-100 mb-8 flex flex-col md:flex-row gap-4 items-center justify-between sticky top-20 z-10 backdrop-blur-md bg-white/90">
                <div className="flex items-center gap-2 overflow-x-auto w-full md:w-auto pb-2 md:pb-0 hide-scrollbar">
                    {['All', 'Pending', 'Today', 'This Week', 'This Month'].map(filter => (
                        <button
                            key={filter}
                            onClick={() => setActiveFilter(filter)}
                            className={`px-4 py-2 rounded-lg text-sm font-bold whitespace-nowrap transition-all
                                ${activeFilter === filter
                                    ? 'bg-primary text-white shadow-md'
                                    : 'bg-gray-100 text-gray-600 hover:bg-gray-200'}`}
                        >
                            {filter}
                        </button>
                    ))}
                </div>

                <div className="relative w-full md:w-64">
                    <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-400 w-4 h-4" />
                    <input
                        type="text"
                        placeholder="Search by Order ID or Token..."
                        value={searchTerm}
                        onChange={(e) => setSearchTerm(e.target.value)}
                        className="w-full pl-10 pr-4 py-2 rounded-lg bg-gray-50 border border-gray-200 focus:outline-none focus:ring-2 focus:ring-primary/20 focus:border-primary font-medium text-sm"
                    />
                </div>
            </div>

            {/* Orders List */}
            {filteredOrders.length === 0 ? (
                <div className="text-center py-24 bg-white rounded-3xl shadow-sm border border-gray-100 animate-fade-in-up">
                    <div className="bg-gray-50 w-24 h-24 rounded-full flex items-center justify-center mx-auto mb-6">
                        <ShoppingBag className="w-12 h-12 text-gray-300" />
                    </div>
                    <h2 className="text-2xl font-bold text-gray-900 mb-2">No orders found</h2>
                    <p className="text-gray-500 mb-8 max-w-sm mx-auto">Try changing your filters or place a new order to get started.</p>
                    {activeFilter !== 'All' && (
                        <button
                            onClick={() => setActiveFilter('All')}
                            className="text-primary font-bold hover:underline"
                        >
                            Clear Filters
                        </button>
                    )}
                </div>
            ) : (
                <div className="space-y-6">
                    {filteredOrders.map((order, index) => (
                        <OrderCard
                            key={order._id}
                            order={order}
                            index={index}
                            onUpdate={handleOrderUpdate}
                        />
                    ))}
                </div>
            )}
        </div>
    );
}

function OrderCard({ order, index, onUpdate }) {
    const { addMultipleToCart } = useCart();
    const [expanded, setExpanded] = useState(false);
    const [actionLoading, setActionLoading] = useState(false);

    const steps = ['Pending', 'Preparing', 'Ready', 'Collected'];
    // Handle cancelled status specially
    const isCancelled = order.status === 'Cancelled';
    const status = (steps.includes(order.status) || isCancelled) ? order.status : 'Pending';
    const currentStepIndex = steps.indexOf(status);

    const getStatusColor = (status) => {
        switch (status) {
            case 'Pending': return 'text-blue-600 bg-blue-50 border-blue-100';
            case 'Preparing': return 'text-amber-600 bg-amber-50 border-amber-100';
            case 'Ready': return 'text-emerald-600 bg-emerald-50 border-emerald-100';
            case 'Collected': return 'text-gray-600 bg-gray-50 border-gray-100';
            case 'Cancelled': return 'text-red-600 bg-red-50 border-red-100';
            default: return 'text-gray-600 bg-gray-50 border-gray-100';
        }
    };

    const handleCancel = async () => {
        if (!window.confirm("Are you sure you want to cancel this order?")) return;

        setActionLoading(true);
        try {
            const res = await api.put(`/orders/${order._id}/cancel`);
            onUpdate(res.data);
            toast.success("Order cancelled successfully");
        } catch (err) {
            toast.error(err.response?.data?.msg || "Failed to cancel order");
        } finally {
            setActionLoading(false);
        }
    };

    const handleReorder = () => {
        const itemsToReorder = order.items.map(item => ({
            id: item.foodItem?._id || item._id, // Handle populated vs raw structure
            name: item.foodItem?.name || item.name,
            price: item.foodItem?.price || item.price,
            image: item.foodItem?.image || item.image,
            category: item.foodItem?.category || 'General',
            quantity: item.quantity
        }));

        addMultipleToCart(itemsToReorder);
        toast.success("Items added to cart! 🛒");
    };

    return (
        <div className={`bg-white rounded-2xl shadow-sm border border-gray-200 overflow-hidden transition-all duration-300 hover:shadow-md ${isCancelled ? 'opacity-75 grayscale-[0.5]' : ''}`}>
            {/* Card Header - Always Visible */}
            <div className="p-6 cursor-pointer" onClick={() => setExpanded(!expanded)}>
                <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">

                    {/* Left: ID & Date */}
                    <div className="flex items-center gap-4">
                        <div className="bg-gray-100 w-16 h-16 rounded-xl flex flex-col items-center justify-center border border-gray-200">
                            <span className="text-[10px] text-gray-500 font-bold uppercase">Token</span>
                            <span className="text-2xl font-black text-gray-900">{order.tokenNumber}</span>
                        </div>
                        <div>
                            <div className="flex items-center gap-2 mb-1">
                                <h3 className="font-bold text-gray-900">Order #{order._id.slice(-6).toUpperCase()}</h3>
                                <div className={`px-2 py-0.5 rounded text-[10px] font-bold uppercase border flex items-center gap-1 ${getStatusColor(order.status)}`}>
                                    <StatusIcon status={order.status} />
                                    {order.status}
                                </div>
                            </div>
                            <p className="text-sm text-gray-500 font-medium">
                                {new Date(order.createdAt).toLocaleDateString('en-US', {
                                    weekday: 'short', month: 'short', day: 'numeric', hour: '2-digit', minute: '2-digit'
                                })}
                            </p>
                        </div>
                    </div>

                    {/* Right: Total & Action */}
                    <div className="flex items-center gap-6">
                        <div className="text-right">
                            <p className="text-xs text-gray-400 font-bold uppercase">Total</p>
                            <p className="text-xl font-black text-gray-900">₹{order.totalAmount}</p>
                        </div>
                        <ChevronRight className={`w-5 h-5 text-gray-400 transition-transform ${expanded ? 'rotate-90' : ''}`} />
                    </div>
                </div>


            </div>

            {/* Expanded Details */}
            {expanded && (
                <div className="bg-gray-50/50 border-t border-gray-100 p-6 animate-fade-in-down">
                    {!isCancelled && order.status !== 'Collected' && (
                        <div className="mb-8 bg-white p-6 rounded-2xl border border-gray-100 shadow-sm">
                            <h4 className="text-xs font-bold text-gray-400 uppercase tracking-wider mb-6">Live Status</h4>
                            <LiveStatusTimeline currentStatus={order.status} createdAt={order.createdAt} />
                        </div>
                    )}

                    {order.status === 'Collected' ? (
                        <PostOrderCompletion order={order} />
                    ) : (
                        <div className="grid md:grid-cols-2 gap-8">
                            <div>
                                <h4 className="text-xs font-bold text-gray-400 uppercase tracking-wider mb-4">Items Ordered</h4>
                                <div className="space-y-3">
                                    {order.items.map((item, idx) => (
                                        <div key={idx} className="flex justify-between items-center text-sm">
                                            <div className="flex items-center gap-3">
                                                <span className="font-bold text-gray-500">{item.quantity}x</span>
                                                <span className="font-medium text-gray-800">{item.foodItem?.name || item.name || 'Unknown Item'}</span>
                                            </div>
                                            <span className="font-bold text-gray-900">₹{item.price * item.quantity}</span>
                                        </div>
                                    ))}
                                </div>

                                <div className="mt-4 pt-4 border-t border-gray-200 flex justify-between items-center">
                                    <span className="font-bold text-gray-900">Grand Total</span>
                                    <span className="font-black text-xl text-primary">₹{order.totalAmount}</span>
                                </div>
                            </div>

                            <div>
                                <h4 className="text-xs font-bold text-gray-400 uppercase tracking-wider mb-4">Order Info</h4>
                                <div className="space-y-4 text-sm">
                                    <div className="flex items-center gap-3 text-gray-600">
                                        <Clock className="w-4 h-4" />
                                        <span className="font-medium">Pickup Slot: <span className="text-gray-900 font-bold">{order.pickupSlot}</span></span>
                                    </div>
                                    <div className="flex items-center gap-3 text-gray-600">
                                        <CheckCircle className="w-4 h-4" />
                                        <span className="font-medium">Payment: <span className="text-green-600 font-bold">{order.paymentStatus === 'Paid' ? 'Paid Online' : 'Cash on Pickup'}</span></span>
                                    </div>

                                    <div className="pt-4 flex gap-3">
                                        {order.status === 'Pending' && (
                                            <button
                                                onClick={(e) => { e.stopPropagation(); handleCancel(); }}
                                                disabled={actionLoading}
                                                className="flex-1 bg-white border border-red-200 text-red-600 px-4 py-2.5 rounded-xl font-bold text-sm hover:bg-red-50 hover:border-red-300 transition-all flex items-center justify-center gap-2"
                                            >
                                                {actionLoading ? <Loader className="w-4 h-4 animate-spin" /> : <XCircle className="w-4 h-4" />}
                                                Cancel Order
                                            </button>
                                        )}

                                        <button
                                            onClick={(e) => { e.stopPropagation(); handleReorder(); }}
                                            className="flex-1 bg-primary text-white px-4 py-2.5 rounded-xl font-bold text-sm hover:bg-primary-hover shadow-lg shadow-primary/20 transition-all flex items-center justify-center gap-2"
                                        >
                                            <RotateCcw className="w-4 h-4" />
                                            Reorder
                                        </button>
                                    </div>
                                </div>
                            </div>
                        </div>
                    )}
                </div>
            )}
        </div>
    );
}

function StatusIcon({ status }) {
    switch (status) {
        case 'Preparing': return <ChefHat className="w-3 h-3" />;
        case 'Ready': return <Package className="w-3 h-3" />;
        case 'Collected': return <CheckCircle className="w-3 h-3" />;
        case 'Cancelled': return <XCircle className="w-3 h-3" />;
        default: return <Clock className="w-3 h-3" />;
    }
}

function LiveStatusTimeline({ currentStatus, createdAt }) {
    const steps = [
        { status: 'Pending', label: 'Order Received', desc: "We've received your order." },
        { status: 'Preparing', label: 'Preparing', desc: "Chef is working on your meal." },
        { status: 'Ready', label: 'Ready for Pickup', desc: "Show your Student ID to collect." },
        { status: 'Collected', label: 'Collected', desc: "Enjoy your meal!" }
    ];

    const currentStepIndex = steps.findIndex(s => s.status === currentStatus);
    const date = new Date(createdAt);

    return (
        <div className="relative pl-4 space-y-8 before:absolute before:inset-0 before:left-2 before:h-full before:w-0.5 before:bg-gray-100">
            {steps.map((step, index) => {
                const isCompleted = index <= currentStepIndex;
                const isCurrent = index === currentStepIndex;

                return (
                    <div key={step.status} className="relative flex items-start gap-4">
                        {/* Timeline Dot */}
                        <div className={`absolute -left-[29px] w-6 h-6 rounded-full border-2 flex items-center justify-center bg-white z-10 transition-all duration-500
                            ${isCompleted ? 'border-primary bg-primary text-white' : 'border-gray-200 text-gray-300'}
                            ${isCurrent ? 'ring-4 ring-primary/20 scale-110' : ''}
                        `}>
                            {isCompleted ? <CheckCircle className="w-3 h-3" /> : <div className="w-2 h-2 rounded-full bg-gray-200" />}
                        </div>

                        {/* Content */}
                        <div className={`flex-1 transition-all duration-500 ${isCompleted ? 'opacity-100' : 'opacity-40 grayscale'}`}>
                            <div className="flex justify-between items-start">
                                <div>
                                    <h5 className={`font-bold text-sm ${isCurrent ? 'text-primary text-lg' : 'text-gray-900'}`}>
                                        {step.label}
                                    </h5>
                                    <p className="text-xs text-gray-500 mt-1">{step.desc}</p>
                                </div>
                                {index === 0 && (
                                    <span className="text-xs font-mono text-gray-400">
                                        {date.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
                                    </span>
                                )}
                                {isCurrent && index !== 0 && (
                                    <span className="text-xs font-bold text-primary animate-pulse">
                                        {new Date().toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
                                    </span>
                                )}
                            </div>
                        </div>
                    </div>
                );
            })}
        </div>
    );
}

import React, { useState, useEffect } from 'react';
import api from '../../api/axios';
import toast from 'react-hot-toast';
import {
    PlusIcon,
    PencilSquareIcon,
    TrashIcon,
    ExclamationTriangleIcon,
    XCircleIcon,
    MagnifyingGlassIcon
} from '@heroicons/react/24/outline';

export default function Inventory() {
    const [items, setItems] = useState([]);
    const [loading, setLoading] = useState(true);
    const [searchTerm, setSearchTerm] = useState('');

    // Modal state
    const [isModalOpen, setIsModalOpen] = useState(false);
    const [editingItem, setEditingItem] = useState(null);
    const [formData, setFormData] = useState({
        itemName: '',
        quantity: 0,
        unit: 'kg',
        lowStockThreshold: 5
    });

    const fetchInventory = async () => {
        try {
            const res = await api.get('/admin/inventory');
            if (res.data.success) {
                setItems(res.data.inventory);
            }
        } catch (error) {
            toast.error('Failed to load inventory');
        } finally {
            setLoading(false);
        }
    };

    useEffect(() => {
        fetchInventory();
    }, []);

    const handleInputChange = (e) => {
        const { name, value } = e.target;
        setFormData(prev => ({ ...prev, [name]: value }));
    };

    const openAddModal = () => {
        setEditingItem(null);
        setFormData({ itemName: '', quantity: 0, unit: 'kg', lowStockThreshold: 5 });
        setIsModalOpen(true);
    };

    const openEditModal = (item) => {
        setEditingItem(item);
        setFormData(item);
        setIsModalOpen(true);
    };

    const handleSubmit = async (e) => {
        e.preventDefault();
        try {
            if (editingItem) {
                await api.put(`/admin/inventory/${editingItem._id}`, formData);
                toast.success('Inventory updated');
            } else {
                await api.post('/admin/inventory', formData);
                toast.success('Raw material added');
            }
            setIsModalOpen(false);
            fetchInventory();
        } catch (error) {
            toast.error('Operation failed');
        }
    };

    const handleDelete = async (id) => {
        if (window.confirm('Are you sure you want to delete this raw material?')) {
            try {
                await api.delete(`/admin/inventory/${id}`);
                toast.success('Material deleted');
                fetchInventory();
            } catch (error) {
                toast.error('Failed to delete');
            }
        }
    };

    // Quick quantity update buttons
    const adjustQuantity = async (item, amount) => {
        const newTotal = Number(item.quantity) + amount;
        if (newTotal < 0) return;

        try {
            await api.put(`/admin/inventory/${item._id}`, { ...item, quantity: newTotal });
            setItems(items.map(i => i._id === item._id ? { ...i, quantity: newTotal } : i));
            // Only toast if it drops below threshold
            if (newTotal <= item.lowStockThreshold && item.quantity > item.lowStockThreshold) {
                toast.error(`${item.itemName} is now LOW STOCK!`);
            }
        } catch (error) {
            toast.error('Failed to update quantity');
        }
    };

    const filteredItems = items.filter(item =>
        item.itemName.toLowerCase().includes(searchTerm.toLowerCase())
    );

    const lowStockItems = items.filter(item => item.quantity <= item.lowStockThreshold);

    return (
        <div className="space-y-6 animate-fade-in">
            <div className="flex flex-col sm:flex-row justify-between sm:items-center gap-4">
                <div>
                    <h1 className="text-2xl font-bold text-gray-800">Inventory Management</h1>
                    <p className="text-gray-500 text-sm mt-1">Track raw materials and get low-stock alerts.</p>
                </div>
                <button
                    onClick={openAddModal}
                    className="flex items-center justify-center gap-2 bg-gradient-to-r from-orange-500 to-red-500 text-white px-5 py-2.5 rounded-xl hover:shadow-lg hover:-translate-y-0.5 transition-all font-medium"
                >
                    <PlusIcon className="h-5 w-5" />
                    Add Material
                </button>
            </div>

            {lowStockItems.length > 0 && (
                <div className="bg-red-50 border-l-4 border-red-500 p-4 rounded-r-lg flex items-start">
                    <ExclamationTriangleIcon className="h-6 w-6 text-red-500 mr-3 flex-shrink-0" />
                    <div>
                        <h3 className="text-red-800 font-bold">Low Stock Alert!</h3>
                        <p className="text-red-700 text-sm mt-1">
                            The following items need to be restocked:
                            <span className="font-semibold ml-1">
                                {lowStockItems.map(i => i.itemName).join(', ')}
                            </span>
                        </p>
                    </div>
                </div>
            )}

            <div className="bg-white rounded-xl shadow-sm border border-gray-100 overflow-hidden">
                <div className="p-4 border-b border-gray-100 bg-gray-50/50 flex flex-col sm:flex-row gap-4 justify-between items-center">
                    <div className="relative w-full sm:w-72">
                        <MagnifyingGlassIcon className="h-5 w-5 absolute left-3 top-1/2 transform -translate-y-1/2 text-gray-400" />
                        <input
                            type="text"
                            placeholder="Search materials..."
                            value={searchTerm}
                            onChange={(e) => setSearchTerm(e.target.value)}
                            className="w-full pl-10 pr-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-orange-500"
                        />
                    </div>
                </div>

                <div className="overflow-x-auto">
                    <table className="min-w-full divide-y divide-gray-200">
                        <thead className="bg-gray-50">
                            <tr>
                                <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Item Name</th>
                                <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Stock Level</th>
                                <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Threshold</th>
                                <th className="px-6 py-3 text-center text-xs font-medium text-gray-500 uppercase tracking-wider">Quick Update</th>
                                <th className="px-6 py-3 text-right text-xs font-medium text-gray-500 uppercase tracking-wider">Actions</th>
                            </tr>
                        </thead>
                        <tbody className="bg-white divide-y divide-gray-200">
                            {loading ? (
                                <tr><td colSpan="5" className="px-6 py-10 text-center">Loading inventory...</td></tr>
                            ) : filteredItems.length === 0 ? (
                                <tr><td colSpan="5" className="px-6 py-10 text-center text-gray-500">No raw materials found.</td></tr>
                            ) : (
                                filteredItems.map((item) => {
                                    const isLow = item.quantity <= item.lowStockThreshold;
                                    return (
                                        <tr key={item._id} className="hover:bg-gray-50 transition-colors">
                                            <td className="px-6 py-4 whitespace-nowrap">
                                                <div className="font-bold text-gray-900">{item.itemName}</div>
                                                <div className="text-xs text-gray-500">Last updated: {new Date(item.lastUpdated).toLocaleDateString()}</div>
                                            </td>
                                            <td className="px-6 py-4 whitespace-nowrap">
                                                <div className={`flex items-center font-bold text-lg ${isLow ? 'text-red-600' : 'text-gray-900'}`}>
                                                    {item.quantity} <span className="text-sm font-medium text-gray-500 ml-1">{item.unit}</span>
                                                    {isLow && <ExclamationTriangleIcon className="h-5 w-5 text-red-500 ml-2 animate-pulse" />}
                                                </div>
                                            </td>
                                            <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-500">
                                                {item.lowStockThreshold} {item.unit}
                                            </td>
                                            <td className="px-6 py-4 whitespace-nowrap text-center text-sm font-medium">
                                                <div className="inline-flex rounded-lg border border-gray-200 p-1 bg-gray-50">
                                                    <button onClick={() => adjustQuantity(item, -1)} className="px-3 text-gray-500 hover:text-red-600 font-bold text-lg">-</button>
                                                    <div className="w-px bg-gray-200 mx-1"></div>
                                                    <button onClick={() => adjustQuantity(item, 1)} className="px-3 text-gray-500 hover:text-green-600 font-bold text-lg">+</button>
                                                </div>
                                            </td>
                                            <td className="px-6 py-4 whitespace-nowrap text-right text-sm font-medium">
                                                <div className="flex justify-end gap-2">
                                                    <button onClick={() => openEditModal(item)} className="p-2 text-blue-600 hover:bg-blue-50 rounded-lg">
                                                        <PencilSquareIcon className="h-5 w-5" />
                                                    </button>
                                                    <button onClick={() => handleDelete(item._id)} className="p-2 text-red-600 hover:bg-red-50 rounded-lg">
                                                        <TrashIcon className="h-5 w-5" />
                                                    </button>
                                                </div>
                                            </td>
                                        </tr>
                                    );
                                })
                            )}
                        </tbody>
                    </table>
                </div>
            </div>

            {/* Modal */}
            {isModalOpen && (
                <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/50 backdrop-blur-sm">
                    <div className="bg-white rounded-2xl shadow-xl w-full max-w-sm overflow-hidden animate-slide-up">
                        <div className="p-6 border-b border-gray-100 flex justify-between items-center">
                            <h2 className="text-xl font-bold">{editingItem ? 'Edit Material' : 'Add Material'}</h2>
                            <button onClick={() => setIsModalOpen(false)} className="text-gray-400 hover:text-gray-600">
                                <XCircleIcon className="h-6 w-6" />
                            </button>
                        </div>

                        <form onSubmit={handleSubmit} className="p-6 space-y-4">
                            <div>
                                <label className="block text-sm font-medium text-gray-700 mb-1">Material Name</label>
                                <input required type="text" name="itemName" value={formData.itemName} onChange={handleInputChange} placeholder="e.g. Tomatoes, Flour" className="w-full px-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-orange-500" />
                            </div>

                            <div className="grid grid-cols-2 gap-4">
                                <div>
                                    <label className="block text-sm font-medium text-gray-700 mb-1">Current Stock</label>
                                    <input required type="number" step="0.1" name="quantity" value={formData.quantity} onChange={handleInputChange} className="w-full px-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-orange-500" />
                                </div>
                                <div>
                                    <label className="block text-sm font-medium text-gray-700 mb-1">Unit</label>
                                    <select required name="unit" value={formData.unit} onChange={handleInputChange} className="w-full px-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-orange-500 bg-white">
                                        <option value="kg">kg</option>
                                        <option value="g">g</option>
                                        <option value="L">Liters (L)</option>
                                        <option value="ml">ml</option>
                                        <option value="pcs">Pieces (pcs)</option>
                                        <option value="pkts">Packets</option>
                                    </select>
                                </div>
                            </div>

                            <div>
                                <label className="block text-sm font-medium text-gray-700 mb-1">Low Stock Alert Threshold</label>
                                <input required type="number" step="0.1" name="lowStockThreshold" value={formData.lowStockThreshold} onChange={handleInputChange} className="w-full px-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-orange-500" />
                                <p className="text-xs text-gray-500 mt-1">You will be alerted when stock falls below this number.</p>
                            </div>

                            <div className="pt-4 border-t border-gray-100 flex justify-end gap-3 mt-6">
                                <button type="button" onClick={() => setIsModalOpen(false)} className="px-5 py-2 text-gray-600 bg-gray-100 rounded-xl hover:bg-gray-200 transition-colors font-medium">Cancel</button>
                                <button type="submit" className="px-5 py-2 text-white bg-gradient-to-r from-orange-500 to-red-500 rounded-xl hover:shadow-lg transition-all font-medium">
                                    {editingItem ? 'Save' : 'Add'}
                                </button>
                            </div>
                        </form>
                    </div>
                </div>
            )}
        </div>
    );
}

import React, { useState, useEffect } from 'react';
import api from '../../api/axios';
import toast from 'react-hot-toast';
import {
    PlusIcon,
    PencilSquareIcon,
    TrashIcon,
    CheckCircleIcon,
    XCircleIcon,
    MagnifyingGlassIcon
} from '@heroicons/react/24/outline';

export default function Menu() {
    const [items, setItems] = useState([]);
    const [loading, setLoading] = useState(true);
    const [searchTerm, setSearchTerm] = useState('');

    // Modal state for Add/Edit
    const [isModalOpen, setIsModalOpen] = useState(false);
    const [editingItem, setEditingItem] = useState(null);
    const [formData, setFormData] = useState({
        name: '',
        category: 'Snacks',
        price: '',
        description: '',
        image: '',
        imageFile: null,
        available: true,
        isVeg: true
    });

    const fetchMenu = async () => {
        try {
            const res = await api.get('/menu/all');
            setItems(res.data);
        } catch (error) {
            toast.error('Failed to load menu');
        } finally {
            setLoading(false);
        }
    };

    useEffect(() => {
        fetchMenu();
    }, []);

    const handleInputChange = (e) => {
        const { name, value, type, checked } = e.target;
        setFormData(prev => ({
            ...prev,
            [name]: type === 'checkbox' ? checked : value
        }));
    };

    const openAddModal = () => {
        setEditingItem(null);
        setFormData({ name: '', category: 'Snacks', price: '', description: '', image: '', imageFile: null, available: true, isVeg: true });
        setIsModalOpen(true);
    };

    const openEditModal = (item) => {
        setEditingItem(item);
        setFormData({ ...item, imageFile: null });
        setIsModalOpen(true);
    };

    const handleSubmit = async (e) => {
        e.preventDefault();
        try {
            const data = new FormData();
            data.append('name', formData.name);
            data.append('category', formData.category);
            data.append('price', formData.price);
            data.append('description', formData.description);
            data.append('available', formData.available);
            data.append('isVeg', formData.isVeg);

            if (formData.imageFile) {
                data.append('imageFile', formData.imageFile);
            } else if (formData.image) {
                data.append('image', formData.image);
            }

            const config = { headers: { 'Content-Type': 'multipart/form-data' } };

            if (editingItem) {
                await api.put(`/menu/${editingItem._id}`, data, config);
                toast.success('Item updated');
            } else {
                await api.post('/menu', data, config);
                toast.success('Item added');
            }
            setIsModalOpen(false);
            fetchMenu();
        } catch (error) {
            toast.error('Operation failed');
        }
    };

    const handleDelete = async (id) => {
        if (window.confirm('Are you sure you want to delete this item?')) {
            try {
                await api.delete(`/menu/${id}`);
                toast.success('Item deleted');
                fetchMenu();
            } catch (error) {
                toast.error('Failed to delete');
            }
        }
    };

    const toggleAvailability = async (item) => {
        try {
            await api.put(`/menu/${item._id}`, { ...item, available: !item.available });
            setItems(items.map(i => i._id === item._id ? { ...i, available: !i.available } : i));
            toast.success(`${item.name} is now ${!item.available ? 'Available' : 'Out of Stock'}`);
        } catch (error) {
            toast.error('Failed to update status');
        }
    };

    const filteredItems = items.filter(item =>
        item.name.toLowerCase().includes(searchTerm.toLowerCase()) ||
        item.category.toLowerCase().includes(searchTerm.toLowerCase())
    );

    const categories = [...new Set(items.map(i => i.category))];
    if (!categories.includes('Snacks')) categories.push('Snacks');
    if (!categories.includes('Meals')) categories.push('Meals');
    if (!categories.includes('Drinks')) categories.push('Drinks');

    return (
        <div className="space-y-6 animate-fade-in relative">
            <div className="flex flex-col sm:flex-row justify-between sm:items-center gap-4">
                <div>
                    <h1 className="text-2xl font-bold text-gray-800">Menu Management</h1>
                    <p className="text-gray-500 text-sm mt-1">Add, edit, and organize your food items.</p>
                </div>
                <button
                    onClick={openAddModal}
                    className="flex items-center justify-center gap-2 bg-gradient-to-r from-orange-500 to-red-500 text-white px-5 py-2.5 rounded-xl hover:shadow-lg hover:-translate-y-0.5 transition-all font-medium"
                >
                    <PlusIcon className="h-5 w-5" />
                    Add New Item
                </button>
            </div>

            <div className="bg-white p-4 rounded-xl shadow-sm border border-gray-100 flex items-center">
                <MagnifyingGlassIcon className="h-5 w-5 text-gray-400 mr-3" />
                <input
                    type="text"
                    placeholder="Search dishes or categories..."
                    value={searchTerm}
                    onChange={(e) => setSearchTerm(e.target.value)}
                    className="w-full outline-none text-gray-700 bg-transparent"
                />
            </div>

            {loading ? (
                <div className="flex justify-center py-20">Loading menu...</div>
            ) : (
                <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
                    {filteredItems.map(item => (
                        <div key={item._id} className="bg-white rounded-2xl shadow-sm border border-gray-100 overflow-hidden hover:shadow-md transition-shadow group flex flex-col">
                            <div className="h-48 relative overflow-hidden bg-gray-100 flex-shrink-0">
                                <img
                                    src={item.image || 'https://via.placeholder.com/300?text=No+Image'}
                                    alt={item.name}
                                    className={`w-full h-full object-cover transition-transform duration-500 group-hover:scale-105 ${!item.available && 'grayscale opacity-50'}`}
                                    onError={(e) => { e.target.src = 'https://via.placeholder.com/300?text=Image+Error' }}
                                />
                                <div className="absolute top-3 inset-x-3 flex justify-between items-start">
                                    <span className={`px-2 py-1 text-xs font-bold rounded-lg shadow-sm ${item.isVeg ? 'bg-green-100 text-green-700' : 'bg-red-100 text-red-700'}`}>
                                        {item.isVeg ? 'VEG' : 'NON-VEG'}
                                    </span>
                                    <span className="px-2 py-1 text-xs font-bold rounded-lg shadow-sm bg-white/90 text-gray-800 backdrop-blur-sm">
                                        {item.category}
                                    </span>
                                </div>
                            </div>

                            <div className="p-5 flex flex-col flex-1">
                                <div className="flex justify-between items-start mb-2">
                                    <h3 className="text-lg font-bold text-gray-900 line-clamp-1">{item.name}</h3>
                                    <span className="text-lg font-extrabold text-orange-600">₹{item.price}</span>
                                </div>
                                <p className="text-sm text-gray-500 line-clamp-2 mb-4 flex-1">{item.description}</p>

                                <div className="flex items-center justify-between border-t border-gray-50 pt-4 mt-auto">
                                    <button
                                        onClick={() => toggleAvailability(item)}
                                        className={`flex items-center gap-1.5 text-sm font-medium ${item.available ? 'text-green-600 hover:text-green-700' : 'text-red-500 hover:text-red-600'}`}
                                    >
                                        {item.available ? <CheckCircleIcon className="h-5 w-5" /> : <XCircleIcon className="h-5 w-5" />}
                                        {item.available ? 'Available' : 'Out of Stock'}
                                    </button>

                                    <div className="flex gap-2">
                                        <button onClick={() => openEditModal(item)} className="p-2 text-blue-600 hover:bg-blue-50 rounded-lg transition-colors" title="Edit">
                                            <PencilSquareIcon className="h-5 w-5" />
                                        </button>
                                        <button onClick={() => handleDelete(item._id)} className="p-2 text-red-600 hover:bg-red-50 rounded-lg transition-colors" title="Delete">
                                            <TrashIcon className="h-5 w-5" />
                                        </button>
                                    </div>
                                </div>
                            </div>
                        </div>
                    ))}
                </div>
            )}

            {/* Add/Edit Modal */}
            {isModalOpen && (
                <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/50 backdrop-blur-sm">
                    <div className="bg-white rounded-2xl shadow-xl w-full max-w-md overflow-hidden animate-slide-up">
                        <div className="p-6 border-b border-gray-100 flex justify-between items-center">
                            <h2 className="text-xl font-bold">{editingItem ? 'Edit Menu Item' : 'Add New Item'}</h2>
                            <button onClick={() => setIsModalOpen(false)} className="text-gray-400 hover:text-gray-600">
                                <XCircleIcon className="h-6 w-6" />
                            </button>
                        </div>

                        <form onSubmit={handleSubmit} className="p-6 space-y-4">
                            <div>
                                <label className="block text-sm font-medium text-gray-700 mb-1">Item Name</label>
                                <input required type="text" name="name" value={formData.name} onChange={handleInputChange} className="w-full px-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-orange-500" />
                            </div>

                            <div className="grid grid-cols-2 gap-4">
                                <div>
                                    <label className="block text-sm font-medium text-gray-700 mb-1">Category</label>
                                    <select required name="category" value={formData.category} onChange={handleInputChange} className="w-full px-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-orange-500 bg-white">
                                        {categories.map(c => <option key={c} value={c}>{c}</option>)}
                                    </select>
                                </div>
                                <div>
                                    <label className="block text-sm font-medium text-gray-700 mb-1">Price (₹)</label>
                                    <input required type="number" name="price" value={formData.price} onChange={handleInputChange} className="w-full px-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-orange-500" />
                                </div>
                            </div>

                            <div>
                                <label className="block text-sm font-medium text-gray-700 mb-1">Upload Image (Optional)</label>
                                <input type="file" accept="image/*" onChange={(e) => setFormData({ ...formData, imageFile: e.target.files[0] })} className="w-full px-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-orange-500 text-sm" />
                                {formData.image && typeof formData.image === 'string' && !formData.image.startsWith('blob:') && (
                                    <p className="text-xs text-gray-500 mt-1 truncate">Current: {formData.image}</p>
                                )}
                            </div>

                            <div>
                                <label className="block text-sm font-medium text-gray-700 mb-1">Description</label>
                                <textarea name="description" value={formData.description} onChange={handleInputChange} rows="2" className="w-full px-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-orange-500 resize-none"></textarea>
                            </div>

                            <div className="flex gap-6 py-2">
                                <label className="flex items-center gap-2 cursor-pointer">
                                    <input type="checkbox" name="isVeg" checked={formData.isVeg} onChange={handleInputChange} className="rounded text-orange-500 focus:ring-orange-500" />
                                    <span className="text-sm font-medium text-gray-700">Vegetarian</span>
                                </label>
                                <label className="flex items-center gap-2 cursor-pointer">
                                    <input type="checkbox" name="available" checked={formData.available} onChange={handleInputChange} className="rounded text-orange-500 focus:ring-orange-500" />
                                    <span className="text-sm font-medium text-gray-700">Currently Available</span>
                                </label>
                            </div>

                            <div className="pt-4 border-t border-gray-100 flex justify-end gap-3">
                                <button type="button" onClick={() => setIsModalOpen(false)} className="px-5 py-2 text-gray-600 bg-gray-100 rounded-xl hover:bg-gray-200 transition-colors font-medium">Cancel</button>
                                <button type="submit" className="px-5 py-2 text-white bg-gradient-to-r from-orange-500 to-red-500 rounded-xl hover:shadow-lg transition-all font-medium">
                                    {editingItem ? 'Save Changes' : 'Add Item'}
                                </button>
                            </div>
                        </form>
                    </div>
                </div>
            )}
        </div>
    );
}

import React, { useState, useEffect } from 'react';
import api from '../../api/axios';
import toast from 'react-hot-toast';
import {
    PaperAirplaneIcon,
    MegaphoneIcon,
    GiftIcon,
    BellAlertIcon,
    TrashIcon
} from '@heroicons/react/24/outline';

export default function Notifications() {
    const [notifications, setNotifications] = useState([]);
    const [loading, setLoading] = useState(true);
    const [formData, setFormData] = useState({
        title: '',
        message: '',
        type: 'announcement'
    });

    const fetchNotifications = async () => {
        try {
            const res = await api.get('/admin/notifications');
            if (res.data.success) {
                setNotifications(res.data.notifications);
            }
        } catch (error) {
            toast.error('Failed to load notifications');
        } finally {
            setLoading(false);
        }
    };

    useEffect(() => {
        fetchNotifications();
    }, []);

    const handleSubmit = async (e) => {
        e.preventDefault();
        try {
            await api.post('/admin/notifications', formData);
            toast.success('Notification sent successfully!');
            setFormData({ title: '', message: '', type: 'announcement' });
            fetchNotifications();
        } catch (error) {
            toast.error('Failed to send notification');
        }
    };

    const handleDelete = async (id) => {
        try {
            await api.delete(`/admin/notifications/${id}`);
            toast.success('Notification deleted');
            setNotifications(notifications.filter(n => n._id !== id));
        } catch (error) {
            toast.error('Failed to delete notification');
        }
    };

    const getTypeIcon = (type) => {
        switch (type) {
            case 'offer': return <GiftIcon className="h-6 w-6 text-purple-500" />;
            case 'alert': return <BellAlertIcon className="h-6 w-6 text-red-500" />;
            default: return <MegaphoneIcon className="h-6 w-6 text-blue-500" />;
        }
    };

    const getTypeColor = (type) => {
        switch (type) {
            case 'offer': return 'bg-purple-100 text-purple-800';
            case 'alert': return 'bg-red-100 text-red-800';
            default: return 'bg-blue-100 text-blue-800';
        }
    };

    return (
        <div className="space-y-6 animate-fade-in max-w-5xl mx-auto">
            <div>
                <h1 className="text-2xl font-bold text-gray-800">Notification Center</h1>
                <p className="text-gray-500 text-sm mt-1">Broadcast announcements, offers, or alerts to all users.</p>
            </div>

            <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">

                {/* Send Notification Form */}
                <div className="lg:col-span-1">
                    <div className="bg-white rounded-2xl shadow-sm border border-gray-100 p-6">
                        <h2 className="text-lg font-bold text-gray-900 mb-4 flex items-center gap-2">
                            <PaperAirplaneIcon className="h-5 w-5 text-orange-500" />
                            Compose Message
                        </h2>
                        <form onSubmit={handleSubmit} className="space-y-4">
                            <div>
                                <label className="block text-sm font-medium text-gray-700 mb-1">Title</label>
                                <input
                                    required
                                    type="text"
                                    value={formData.title}
                                    onChange={(e) => setFormData({ ...formData, title: e.target.value })}
                                    placeholder="e.g. Canteen closed tomorrow"
                                    className="w-full px-4 py-2 border border-gray-300 rounded-xl focus:ring-2 focus:ring-orange-500 bg-gray-50 focus:bg-white transition-colors"
                                />
                            </div>

                            <div>
                                <label className="block text-sm font-medium text-gray-700 mb-1">Type</label>
                                <select
                                    value={formData.type}
                                    onChange={(e) => setFormData({ ...formData, type: e.target.value })}
                                    className="w-full px-4 py-2 border border-gray-300 rounded-xl focus:ring-2 focus:ring-orange-500 bg-gray-50 focus:bg-white transition-colors"
                                >
                                    <option value="announcement">General Announcement</option>
                                    <option value="offer">Special Offer</option>
                                    <option value="alert">Alert / Emergency</option>
                                </select>
                            </div>

                            <div>
                                <label className="block text-sm font-medium text-gray-700 mb-1">Message Body</label>
                                <textarea
                                    required
                                    rows="4"
                                    value={formData.message}
                                    onChange={(e) => setFormData({ ...formData, message: e.target.value })}
                                    placeholder="Type your message here..."
                                    className="w-full px-4 py-2 border border-gray-300 rounded-xl focus:ring-2 focus:ring-orange-500 bg-gray-50 focus:bg-white transition-colors resize-none"
                                ></textarea>
                            </div>

                            <button type="submit" className="w-full flex items-center justify-center gap-2 bg-gradient-to-r from-orange-500 to-red-500 text-white px-5 py-3 rounded-xl hover:shadow-lg hover:-translate-y-0.5 transition-all font-bold">
                                <PaperAirplaneIcon className="h-5 w-5" />
                                Send Broadcast
                            </button>
                        </form>
                    </div>
                </div>

                {/* Notification History */}
                <div className="lg:col-span-2 space-y-4">
                    <h2 className="text-lg font-bold text-gray-900 px-1">Recent Broadcasts</h2>

                    {loading ? (
                        <div className="bg-white rounded-2xl p-10 text-center text-gray-500 border border-gray-100 shadow-sm">Loading history...</div>
                    ) : notifications.length === 0 ? (
                        <div className="bg-white rounded-2xl p-10 text-center border border-gray-100 shadow-sm">
                            <MegaphoneIcon className="h-12 w-12 mx-auto text-gray-300 mb-3" />
                            <h3 className="text-gray-900 font-medium">No active notifications</h3>
                            <p className="text-gray-500 text-sm mt-1">Sent messages will appear here.</p>
                        </div>
                    ) : (
                        notifications.map((notif) => (
                            <div key={notif._id} className="bg-white rounded-2xl p-5 shadow-sm border border-gray-100 flex gap-4 transition-all hover:shadow-md relative group">
                                <div className="flex-shrink-0 mt-1">
                                    <div className="w-12 h-12 rounded-full bg-gray-50 flex items-center justify-center border border-gray-100">
                                        {getTypeIcon(notif.type)}
                                    </div>
                                </div>
                                <div className="flex-1">
                                    <div className="flex justify-between items-start">
                                        <h3 className="font-bold text-gray-900 text-lg">{notif.title}</h3>
                                        <span className={`px-2.5 py-1 rounded-lg text-xs font-bold uppercase tracking-wide ${getTypeColor(notif.type)}`}>
                                            {notif.type}
                                        </span>
                                    </div>
                                    <p className="text-gray-600 mt-2 text-sm leading-relaxed">{notif.message}</p>
                                    <p className="text-gray-400 text-xs mt-3 font-medium">
                                        {new Date(notif.createdAt).toLocaleString([], { dateStyle: 'medium', timeStyle: 'short' })}
                                    </p>
                                </div>
                                <button
                                    onClick={() => handleDelete(notif._id)}
                                    className="absolute top-4 right-4 p-2 text-gray-400 hover:text-red-500 hover:bg-red-50 rounded-lg opacity-0 group-hover:opacity-100 transition-all"
                                    title="Delete notification"
                                >
                                    <TrashIcon className="h-5 w-5" />
                                </button>
                            </div>
                        ))
                    )}
                </div>

            </div>
        </div>
    );
}

import React, { useState, useEffect } from 'react';
import api from '../../api/axios';
import toast from 'react-hot-toast';
import { io } from 'socket.io-client';
import {
    MagnifyingGlassIcon,
    PrinterIcon,
    ChevronDownIcon,
    ExclamationTriangleIcon
} from '@heroicons/react/24/outline';

export default function Orders() {
    const [orders, setOrders] = useState([]);
    const [loading, setLoading] = useState(true);
    const [searchTerm, setSearchTerm] = useState('');
    const [filterStatus, setFilterStatus] = useState('All');

    const fetchOrders = async () => {
        try {
            const res = await api.get('/orders/all'); // Need to ensure JWT has admin role or public for now
            setOrders(res.data);
        } catch (error) {
            console.error('Failed to fetch orders', error);
            toast.error('Failed to load orders');
        } finally {
            setLoading(false);
        }
    };

    useEffect(() => {
        fetchOrders();

        // Socket.io for new order real-time updates
        const socket = io('http://localhost:5000');

        socket.on('connect', () => {
            console.log('Admin Socket connected for real-time orders');
        });

        socket.on('newOrderReceived', (newOrder) => {
            // Check if we already have it to avoid duplicates
            setOrders(prevOrders => {
                if (!prevOrders.some(o => o._id === newOrder._id)) {
                    toast.success(`New Order Received: #${newOrder.tokenNumber}`, {
                        icon: '🔥',
                        duration: 5000
                    });
                    // Add the new order at the beginning of the list
                    return [newOrder, ...prevOrders];
                }
                return prevOrders;
            });
        });

        socket.on('orderStatusUpdated', (updatedOrder) => {
            setOrders(prevOrders => prevOrders.map(o => o._id === updatedOrder._id ? { ...o, status: updatedOrder.status } : o));
        });

        return () => {
            socket.disconnect();
        };
    }, []);

    const updateOrderStatus = async (orderId, newStatus) => {
        try {
            await api.put(`/orders/${orderId}/status`, { status: newStatus });
            toast.success(`Order marked as ${newStatus}`);
            // Update local state without refetching to feel snappier
            setOrders(orders.map(o => o._id === orderId ? { ...o, status: newStatus } : o));
        } catch (error) {
            toast.error('Failed to update status');
        }
    };

    const handlePrint = (order) => {
        // Basic print bill functionality
        const printWindow = window.open('', '', 'width=600,height=800');
        printWindow.document.write(`
            <html>
                <head>
                    <title>Bill - ${order.tokenNumber}</title>
                    <style>
                        body { font-family: monospace; padding: 20px; }
                        h2 { text-align: center; }
                        table { width: 100%; border-collapse: collapse; margin-top: 20px; }
                        th, td { border-bottom: 1px dashed #000; padding: 5px; text-align: left; }
                        .total { font-weight: bold; font-size: 1.2em; text-align: right; margin-top: 10px; }
                    </style>
                </head>
                <body>
                    <h2>QuickBite Canteen</h2>
                    <p>Token: ${order.tokenNumber}</p>
                    <p>Customer: ${order.user?.name || 'Unknown'}</p>
                    <p>Date: ${new Date(order.createdAt).toLocaleString()}</p>
                    ${order.instructions ? `<p><strong>Instructions:</strong> ${order.instructions}</p>` : ''}
                    <table>
                        <thead>
                            <tr>
                                <th>Item</th>
                                <th>Qty</th>
                                <th>Price</th>
                            </tr>
                        </thead>
                        <tbody>
                            ${order.items.map(i => `
                                <tr>
                                    <td>${i.name}</td>
                                    <td>${i.quantity}</td>
                                    <td>${i.price * i.quantity}</td>
                                </tr>
                            `).join('')}
                        </tbody>
                    </table>
                    <div class="total">Total: ₹${order.totalAmount}</div>
                    <script>
                        window.onload = function() { window.print(); window.close(); }
                    </script>
                </body>
            </html>
        `);
        printWindow.document.close();
    };

    // Derived filtered data
    const filteredOrders = orders.filter(o => {
        const matchesSearch =
            o.tokenNumber.toLowerCase().includes(searchTerm.toLowerCase()) ||
            (o.user?.name || '').toLowerCase().includes(searchTerm.toLowerCase());
        const matchesStatus = filterStatus === 'All' || o.status === filterStatus;
        return matchesSearch && matchesStatus;
    });

    const statusColors = {
        'Pending': 'bg-yellow-100 text-yellow-800',
        'Preparing': 'bg-blue-100 text-blue-800',
        'Ready': 'bg-green-100 text-green-800',
        'Collected': 'bg-gray-100 text-gray-800',
        'Cancelled': 'bg-red-100 text-red-800',
    };

    return (
        <div className="space-y-6 animate-fade-in">
            <div className="flex flex-col md:flex-row justify-between md:items-center gap-4">
                <div>
                    <h1 className="text-2xl font-bold text-gray-800">Order Management</h1>
                    <p className="text-gray-500 text-sm mt-1">Review and manage all incoming orders</p>
                </div>

                <div className="flex flex-col sm:flex-row gap-3">
                    <div className="relative">
                        <MagnifyingGlassIcon className="h-5 w-5 absolute left-3 top-1/2 transform -translate-y-1/2 text-gray-400" />
                        <input
                            type="text"
                            placeholder="Search token or user..."
                            value={searchTerm}
                            onChange={(e) => setSearchTerm(e.target.value)}
                            className="pl-10 pr-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-orange-500 focus:border-orange-500 w-full sm:w-64"
                        />
                    </div>
                    <select
                        value={filterStatus}
                        onChange={(e) => setFilterStatus(e.target.value)}
                        className="py-2 pl-3 pr-10 border border-gray-300 bg-white rounded-lg focus:ring-2 focus:ring-orange-500 focus:border-orange-500"
                    >
                        <option value="All">All Status</option>
                        <option value="Pending">Pending</option>
                        <option value="Preparing">Preparing</option>
                        <option value="Ready">Ready</option>
                        <option value="Collected">Collected</option>
                        <option value="Cancelled">Cancelled</option>
                    </select>
                </div>
            </div>

            {loading ? (
                <div className="flex justify-center py-20">Loading orders...</div>
            ) : filteredOrders.length === 0 ? (
                <div className="text-center py-20 bg-white rounded-xl border border-gray-100">
                    <QueueListIcon className="h-12 w-12 mx-auto text-gray-300 mb-4" />
                    <h3 className="text-lg font-medium text-gray-900">No orders found</h3>
                    <p className="text-gray-500">Try adjusting your search or filters.</p>
                </div>
            ) : (
                <div className="bg-white rounded-xl shadow-sm border border-gray-100 overflow-hidden">
                    <div className="overflow-x-auto">
                        <table className="min-w-full divide-y divide-gray-200">
                            <thead className="bg-gray-50">
                                <tr>
                                    <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Token</th>
                                    <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Customer</th>
                                    <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Items</th>
                                    <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Total</th>
                                    <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Status</th>
                                    <th className="px-6 py-3 text-right text-xs font-medium text-gray-500 uppercase tracking-wider">Actions</th>
                                </tr>
                            </thead>
                            <tbody className="bg-white divide-y divide-gray-200">
                                {filteredOrders.map((order) => (
                                    <tr key={order._id} className="hover:bg-gray-50 transition-colors">
                                        <td className="px-6 py-4 whitespace-nowrap">
                                            <div className="font-bold text-gray-900">#{order.tokenNumber}</div>
                                            <div className="text-sm text-gray-500">{new Date(order.createdAt).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}</div>
                                        </td>
                                        <td className="px-6 py-4 whitespace-nowrap">
                                            <div className="text-sm font-medium text-gray-900">{order.user?.name || 'Guest'}</div>
                                            {/* <div className="text-sm text-gray-500">{order.user?.phone || 'No phone'}</div> */}
                                        </td>
                                        <td className="px-6 py-4">
                                            <div className="text-sm text-gray-900 max-w-xs truncate">
                                                {order.items.map(i => `${i.quantity}x ${i.name}`).join(', ')}
                                            </div>
                                            {order.instructions && (
                                                <div className="text-xs text-orange-600 bg-orange-50 mt-1 p-1 rounded-sm border border-orange-100 italic truncate max-w-xs">
                                                    Note: {order.instructions}
                                                </div>
                                            )}
                                            <div className="text-xs text-gray-500 mt-1">Slot: {order.pickupSlot || 'ASAP'}</div>
                                        </td>
                                        <td className="px-6 py-4 whitespace-nowrap">
                                            <div className="text-sm font-bold text-gray-900">₹{order.totalAmount}</div>
                                            <div className="text-xs text-green-600 font-medium">
                                                {order.paymentStatus}
                                            </div>
                                        </td>
                                        <td className="px-6 py-4 whitespace-nowrap">
                                            <span className={`px-2 inline-flex text-xs leading-5 font-semibold rounded-full ${statusColors[order.status] || 'bg-gray-100 text-gray-800'}`}>
                                                {order.status}
                                            </span>
                                        </td>
                                        <td className="px-6 py-4 whitespace-nowrap text-right text-sm font-medium">
                                            <div className="flex items-center justify-end space-x-2">

                                                {/* Status Dropdown */}
                                                <div className="relative inline-block text-left group">
                                                    <button type="button" className="inline-flex justify-center items-center w-full px-4 py-2 text-sm font-medium text-gray-700 bg-white border border-gray-300 rounded-md hover:bg-gray-50 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-orange-500">
                                                        Update Status
                                                        <ChevronDownIcon className="-mr-1 ml-2 h-4 w-4" />
                                                    </button>

                                                    {/* Invisible bridge wrapper */}
                                                    <div className="absolute right-0 top-full pt-1 w-40 hidden group-hover:block z-50">
                                                        <div className="origin-top-right rounded-md shadow-lg bg-white ring-1 ring-black ring-opacity-5 divide-y divide-gray-100">
                                                            <div className="py-1">
                                                                {['Pending', 'Preparing', 'Ready', 'Collected', 'Cancelled'].map(s => (
                                                                    <button
                                                                        key={s}
                                                                        onClick={() => updateOrderStatus(order._id, s)}
                                                                        className="block w-full text-left px-4 py-2 text-sm text-gray-700 hover:bg-gray-100 hover:text-gray-900"
                                                                    >
                                                                        Mark {s}
                                                                    </button>
                                                                ))}
                                                            </div>
                                                        </div>
                                                    </div>
                                                </div>

                                                {/* Print Bill Button */}
                                                <button
                                                    onClick={() => handlePrint(order)}
                                                    title="Print Bill"
                                                    className="p-2 text-gray-400 hover:text-orange-600 border border-gray-300 rounded-md hover:bg-orange-50 transition-colors"
                                                >
                                                    <PrinterIcon className="h-5 w-5" />
                                                </button>

                                            </div>
                                        </td>
                                    </tr>
                                ))}
                            </tbody>
                        </table>
                    </div>
                </div>
            )
            }
        </div >
    );
}

import React, { useState, useEffect } from 'react';
import api from '../../api/axios';
import {
    BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer,
    LineChart, Line, AreaChart, Area, PieChart, Pie, Cell
} from 'recharts';
import {
    ArrowDownTrayIcon,
    CalendarIcon
} from '@heroicons/react/24/outline';
import toast from 'react-hot-toast';

export default function Reports() {
    const [loading, setLoading] = useState(true);
    const [orders, setOrders] = useState([]);

    useEffect(() => {
        const fetchAllData = async () => {
            try {
                // Fetching all orders to compute analytics locally for demo
                // In production, backend should compute tight aggregations
                const res = await api.get('/orders/all');
                setOrders(res.data);
            } catch (error) {
                toast.error('Failed to load report data');
            } finally {
                setLoading(false);
            }
        };
        fetchAllData();
    }, []);

    // 1. Process Data: Peak Hours Map
    const hoursMap = {};
    orders.forEach(o => {
        const hour = new Date(o.createdAt).getHours();
        hoursMap[hour] = (hoursMap[hour] || 0) + 1;
    });
    const peakHoursData = Object.keys(hoursMap).map(h => ({
        hour: `${h}:00`,
        orders: hoursMap[h]
    })).sort((a, b) => parseInt(a.hour) - parseInt(b.hour));

    // 2. Process Data: Most Ordered Items
    const itemsMap = {};
    orders.forEach(o => {
        o.items.forEach(i => {
            itemsMap[i.name] = (itemsMap[i.name] || 0) + i.quantity;
        });
    });
    const topItemsData = Object.keys(itemsMap)
        .map(name => ({ name, quantity: itemsMap[name] }))
        .sort((a, b) => b.quantity - a.quantity)
        .slice(0, 5); // Top 5

    const COLORS = ['#F97316', '#F59E0B', '#10B981', '#3B82F6', '#8B5CF6'];

    const downloadCSV = () => {
        if (orders.length === 0) return toast.error('No data to export');

        let csvContent = "data:text/csv;charset=utf-8,";
        csvContent += "Date,Token,Customer,Total Amount,Status\n";

        orders.forEach(o => {
            const row = [
                `"${new Date(o.createdAt).toLocaleDateString()}"`,
                `"${o.tokenNumber}"`,
                `"${o.user?.name || 'Guest'}"`,
                `"${o.totalAmount}"`,
                `"${o.status}"`
            ].join(",");
            csvContent += row + "\r\n";
        });

        const encodedUri = encodeURI(csvContent);
        const link = document.createElement("a");
        link.setAttribute("href", encodedUri);
        link.setAttribute("download", `quickbite_report_${new Date().toISOString().split('T')[0]}.csv`);
        document.body.appendChild(link);
        link.click();
        document.body.removeChild(link);
        toast.success('Download started');
    };

    return (
        <div className="space-y-6 animate-fade-in">
            <div className="flex flex-col sm:flex-row justify-between sm:items-center gap-4">
                <div>
                    <h1 className="text-2xl font-bold text-gray-800">Reports & Analytics 📈</h1>
                    <p className="text-gray-500 text-sm mt-1">Deep dive into canteen performance and student preferenes.</p>
                </div>

                <button
                    onClick={downloadCSV}
                    className="flex items-center justify-center gap-2 bg-white border border-gray-300 text-gray-700 font-medium px-5 py-2.5 rounded-xl hover:bg-gray-50 hover:shadow-sm transition-all shadow-sm"
                >
                    <ArrowDownTrayIcon className="h-5 w-5" />
                    Download CSV Report
                </button>
            </div>

            {loading ? (
                <div className="flex justify-center py-20">Computing analytics...</div>
            ) : (
                <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">

                    {/* Top Items Pie Chart */}
                    <div className="bg-white rounded-2xl shadow-sm border border-gray-100 p-6">
                        <h2 className="text-lg font-bold text-gray-900 mb-6">Most Ordered Items</h2>
                        <div className="h-80 w-full flex justify-center">
                            {topItemsData.length > 0 ? (
                                <ResponsiveContainer width="100%" height="100%">
                                    <PieChart>
                                        <Pie
                                            data={topItemsData}
                                            cx="50%"
                                            cy="50%"
                                            innerRadius={80}
                                            outerRadius={110}
                                            paddingAngle={5}
                                            dataKey="quantity"
                                        >
                                            {topItemsData.map((entry, index) => (
                                                <Cell key={`cell-${index}`} fill={COLORS[index % COLORS.length]} />
                                            ))}
                                        </Pie>
                                        <Tooltip
                                            contentStyle={{ borderRadius: '12px', border: 'none', boxShadow: '0 4px 6px -1px rgba(0, 0, 0, 0.1)' }}
                                            formatter={(value, name) => [value + ' orders', name]}
                                        />
                                    </PieChart>
                                </ResponsiveContainer>
                            ) : <div className="text-gray-400 mt-20">No order data yet</div>}
                        </div>
                        {/* Legend */}
                        <div className="mt-4 flex flex-col gap-2">
                            {topItemsData.map((item, index) => (
                                <div key={item.name} className="flex justify-between items-center text-sm">
                                    <div className="flex items-center gap-2">
                                        <div className="w-3 h-3 rounded-full" style={{ backgroundColor: COLORS[index % COLORS.length] }}></div>
                                        <span className="text-gray-700 font-medium">{item.name}</span>
                                    </div>
                                    <span className="text-gray-900 font-bold">{item.quantity}</span>
                                </div>
                            ))}
                        </div>
                    </div>

                    {/* Peak Hours Chart */}
                    <div className="bg-white rounded-2xl shadow-sm border border-gray-100 p-6">
                        <h2 className="text-lg font-bold text-gray-900 mb-6">Peak Operational Hours</h2>
                        <div className="h-80 w-full">
                            {peakHoursData.length > 0 ? (
                                <ResponsiveContainer width="100%" height="100%">
                                    <AreaChart data={peakHoursData} margin={{ top: 10, right: 30, left: 0, bottom: 0 }}>
                                        <defs>
                                            <linearGradient id="colorOrders" x1="0" y1="0" x2="0" y2="1">
                                                <stop offset="5%" stopColor="#F97316" stopOpacity={0.3} />
                                                <stop offset="95%" stopColor="#F97316" stopOpacity={0} />
                                            </linearGradient>
                                        </defs>
                                        <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#E5E7EB" />
                                        <XAxis dataKey="hour" axisLine={false} tickLine={false} tick={{ fill: '#6B7280', fontSize: 12 }} dy={10} />
                                        <YAxis axisLine={false} tickLine={false} tick={{ fill: '#6B7280', fontSize: 12 }} />
                                        <Tooltip contentStyle={{ borderRadius: '12px', border: 'none', boxShadow: '0 4px 6px -1px rgba(0, 0, 0, 0.1)' }} />
                                        <Area type="monotone" dataKey="orders" stroke="#F97316" strokeWidth={3} fillOpacity={1} fill="url(#colorOrders)" />
                                    </AreaChart>
                                </ResponsiveContainer>
                            ) : <div className="flex justify-center mt-20 text-gray-400">No hourly data yet</div>}
                        </div>
                    </div>
                </div>
            )}
        </div>
    );
}

import React, { useState, useEffect } from 'react';
import api from '../../api/axios';
import toast from 'react-hot-toast';
import {
    ClockIcon,
    AtSymbolIcon,
    PhoneIcon,
    ReceiptPercentIcon,
    Cog8ToothIcon,
    CheckBadgeIcon
} from '@heroicons/react/24/outline';

export default function Settings() {
    const [settings, setSettings] = useState({
        canteenName: 'QuickBite Canteen',
        openingTime: '08:00 AM',
        closingTime: '06:00 PM',
        taxPercentage: 5,
        contactEmail: 'admin@quickbite.com',
        contactPhone: '+91 9876543210',
        deliveryRules: 'Pickup only at the counter.',
        isOpen: true
    });
    const [loading, setLoading] = useState(true);
    const [saving, setSaving] = useState(false);

    useEffect(() => {
        const fetchSettings = async () => {
            try {
                const res = await api.get('/admin/settings');
                if (res.data.success && res.data.settings) {
                    setSettings(res.data.settings);
                }
            } catch (error) {
                toast.error('Failed to load settings');
            } finally {
                setLoading(false);
            }
        };
        fetchSettings();
    }, []);

    const handleChange = (e) => {
        const { name, value, type, checked } = e.target;
        setSettings({
            ...settings,
            [name]: type === 'checkbox' ? checked : value
        });
    };

    const handleSave = async (e) => {
        e.preventDefault();
        setSaving(true);
        try {
            await api.put('/admin/settings', settings);
            toast.success('Settings saved successfully');
        } catch (error) {
            toast.error('Failed to save settings');
        } finally {
            setSaving(false);
        }
    };

    if (loading) return <div className="flex justify-center p-20">Loading settings...</div>;

    return (
        <div className="max-w-4xl mx-auto space-y-6 animate-fade-in">
            <div>
                <h1 className="text-2xl font-bold text-gray-800">Canteen Configuration</h1>
                <p className="text-gray-500 text-sm mt-1">Manage global timings, tax rates, and contact info.</p>
            </div>

            <div className="bg-white rounded-2xl shadow-sm border border-gray-100 overflow-hidden">
                <form onSubmit={handleSave}>

                    {/* Primary Status Toggle */}
                    <div className="p-6 border-b border-gray-100 bg-gray-50/50 flex items-center justify-between">
                        <div>
                            <h2 className="text-lg font-bold text-gray-900 flex items-center gap-2">
                                <Cog8ToothIcon className="h-5 w-5 text-gray-500" /> Operational Status
                            </h2>
                            <p className="text-sm text-gray-500">Toggle whether the canteen is currently accepting orders.</p>
                        </div>
                        <label className="relative inline-flex items-center cursor-pointer">
                            <input
                                type="checkbox"
                                name="isOpen"
                                checked={settings.isOpen}
                                onChange={handleChange}
                                className="sr-only peer"
                            />
                            <div className="w-14 h-7 bg-gray-200 peer-focus:outline-none rounded-full peer peer-checked:after:translate-x-full peer-checked:after:border-white after:content-[''] after:absolute after:top-[2px] after:left-[2px] after:bg-white after:border-gray-300 after:border after:rounded-full after:h-6 after:w-6 after:transition-all peer-checked:bg-green-500"></div>
                            <span className={`ml-3 text-sm font-bold ${settings.isOpen ? 'text-green-600' : 'text-gray-500'}`}>
                                {settings.isOpen ? 'ACCEPTING ORDERS' : 'CLOSED'}
                            </span>
                        </label>
                    </div>

                    <div className="p-6 md:p-8 space-y-8">
                        {/* Timings */}
                        <div>
                            <h3 className="text-md font-bold text-gray-900 mb-4 flex items-center gap-2 border-b border-gray-100 pb-2">
                                <ClockIcon className="h-5 w-5 text-orange-500" /> Operational Hours
                            </h3>
                            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                                <div>
                                    <label className="block text-sm font-medium text-gray-700 mb-1">Opening Time</label>
                                    <input
                                        type="time"
                                        name="openingTime"
                                        value={settings.openingTime}
                                        onChange={handleChange}
                                        className="w-full px-4 py-3 bg-gray-50 border border-gray-200 rounded-xl focus:ring-2 focus:ring-orange-500 focus:bg-white"
                                    />
                                </div>
                                <div>
                                    <label className="block text-sm font-medium text-gray-700 mb-1">Closing Time</label>
                                    <input
                                        type="time"
                                        name="closingTime"
                                        value={settings.closingTime}
                                        onChange={handleChange}
                                        className="w-full px-4 py-3 bg-gray-50 border border-gray-200 rounded-xl focus:ring-2 focus:ring-orange-500 focus:bg-white"
                                    />
                                </div>
                            </div>
                        </div>

                        {/* Financials & Rules */}
                        <div>
                            <h3 className="text-md font-bold text-gray-900 mb-4 flex items-center gap-2 border-b border-gray-100 pb-2">
                                <ReceiptPercentIcon className="h-5 w-5 text-orange-500" /> Financials & Rules
                            </h3>
                            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                                <div>
                                    <label className="block text-sm font-medium text-gray-700 mb-1">GST / Tax Percentage (%)</label>
                                    <input
                                        type="number"
                                        name="taxPercentage"
                                        value={settings.taxPercentage}
                                        onChange={handleChange}
                                        step="0.1"
                                        className="w-full px-4 py-3 bg-gray-50 border border-gray-200 rounded-xl focus:ring-2 focus:ring-orange-500 focus:bg-white"
                                    />
                                </div>
                                <div>
                                    <label className="block text-sm font-medium text-gray-700 mb-1">Pickup Policy</label>
                                    <input
                                        type="text"
                                        name="deliveryRules"
                                        value={settings.deliveryRules}
                                        onChange={handleChange}
                                        className="w-full px-4 py-3 bg-gray-50 border border-gray-200 rounded-xl focus:ring-2 focus:ring-orange-500 focus:bg-white"
                                    />
                                </div>
                            </div>
                        </div>

                        {/* Contact Info */}
                        <div>
                            <h3 className="text-md font-bold text-gray-900 mb-4 flex items-center gap-2 border-b border-gray-100 pb-2">
                                <AtSymbolIcon className="h-5 w-5 text-orange-500" /> Contact Information
                            </h3>
                            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                                <div>
                                    <label className="block text-sm font-medium text-gray-700 mb-1">Support Email</label>
                                    <div className="relative">
                                        <AtSymbolIcon className="h-5 w-5 absolute left-3 top-1/2 -translate-y-1/2 text-gray-400" />
                                        <input
                                            type="email"
                                            name="contactEmail"
                                            value={settings.contactEmail}
                                            onChange={handleChange}
                                            className="w-full pl-10 pr-4 py-3 bg-gray-50 border border-gray-200 rounded-xl focus:ring-2 focus:ring-orange-500 focus:bg-white"
                                        />
                                    </div>
                                </div>
                                <div>
                                    <label className="block text-sm font-medium text-gray-700 mb-1">Helpdesk Phone</label>
                                    <div className="relative">
                                        <PhoneIcon className="h-5 w-5 absolute left-3 top-1/2 -translate-y-1/2 text-gray-400" />
                                        <input
                                            type="text"
                                            name="contactPhone"
                                            value={settings.contactPhone}
                                            onChange={handleChange}
                                            className="w-full pl-10 pr-4 py-3 bg-gray-50 border border-gray-200 rounded-xl focus:ring-2 focus:ring-orange-500 focus:bg-white"
                                        />
                                    </div>
                                </div>
                            </div>
                        </div>
                    </div>

                    <div className="p-6 border-t border-gray-100 bg-gray-50/50 flex justify-end">
                        <button
                            type="submit"
                            disabled={saving}
                            className="flex items-center justify-center gap-2 bg-gradient-to-r from-orange-500 to-red-500 text-white font-bold px-8 py-3 rounded-xl hover:shadow-lg hover:-translate-y-0.5 transition-all disabled:opacity-70 disabled:hover:translate-y-0"
                        >
                            {saving ? 'Saving...' : <><CheckBadgeIcon className="h-6 w-6" /> Save Configuration</>}
                        </button>
                    </div>

                </form>
            </div>
        </div>
    );
}

import React, { useState, useEffect } from 'react';
import api from '../../api/axios';
import toast from 'react-hot-toast';
import {
    MagnifyingGlassIcon,
    ShieldCheckIcon,
    NoSymbolIcon,
    TrashIcon
} from '@heroicons/react/24/outline';

export default function Users() {
    const [users, setUsers] = useState([]);
    const [loading, setLoading] = useState(true);
    const [searchTerm, setSearchTerm] = useState('');

    const fetchUsers = async () => {
        try {
            const res = await api.get('/admin/users');
            if (res.data.success) {
                setUsers(res.data.users);
            }
        } catch (error) {
            toast.error('Failed to load users');
        } finally {
            setLoading(false);
        }
    };

    useEffect(() => {
        fetchUsers();
    }, []);

    const toggleRole = async (user) => {
        const newRole = user.role === 'admin' ? 'student' : 'admin';
        if (window.confirm(`Are you sure you want to make ${user.name} an ${newRole}?`)) {
            try {
                await api.put(`/admin/users/${user._id}`, { role: newRole });
                toast.success('User role updated');
                // Optimistic UI update
                setUsers(users.map(u => u._id === user._id ? { ...u, role: newRole } : u));
            } catch (error) {
                toast.error('Failed to update role');
            }
        }
    };

    const handleDelete = async (id) => {
        if (window.confirm('Delete this user permanently? This action cannot be undone.')) {
            try {
                await api.delete(`/admin/users/${id}`);
                toast.success('User deleted');
                setUsers(users.filter(u => u._id !== id));
            } catch (error) {
                toast.error('Failed to delete user');
            }
        }
    };

    const toggleBlock = (user) => {
        // Mock block functionality since we don't have an isBlocked schema property yet
        toast.success(`User ${user.name} has been ${user.isBlocked ? 'unblocked' : 'blocked'} (UI Only Demo)`);
        setUsers(users.map(u => u._id === user._id ? { ...u, isBlocked: !u.isBlocked } : u));
    };

    const filteredUsers = users.filter(u =>
        u.name.toLowerCase().includes(searchTerm.toLowerCase()) ||
        u.email.toLowerCase().includes(searchTerm.toLowerCase())
    );

    return (
        <div className="space-y-6 animate-fade-in">
            <div className="flex flex-col sm:flex-row justify-between sm:items-center gap-4">
                <div>
                    <h1 className="text-2xl font-bold text-gray-800">User Management</h1>
                    <p className="text-gray-500 text-sm mt-1">Manage registered students and staff roles.</p>
                </div>

                <div className="relative w-full sm:w-72">
                    <MagnifyingGlassIcon className="h-5 w-5 absolute left-3 top-1/2 transform -translate-y-1/2 text-gray-400" />
                    <input
                        type="text"
                        placeholder="Search by name or email..."
                        value={searchTerm}
                        onChange={(e) => setSearchTerm(e.target.value)}
                        className="w-full pl-10 pr-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-orange-500 bg-white shadow-sm"
                    />
                </div>
            </div>

            <div className="bg-white rounded-xl shadow-sm border border-gray-100 overflow-hidden">
                <div className="overflow-x-auto">
                    <table className="min-w-full divide-y divide-gray-200">
                        <thead className="bg-gray-50">
                            <tr>
                                <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">User</th>
                                <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Contact</th>
                                <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Role</th>
                                <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Joined</th>
                                <th className="px-6 py-3 text-right text-xs font-medium text-gray-500 uppercase tracking-wider">Actions</th>
                            </tr>
                        </thead>
                        <tbody className="bg-white divide-y divide-gray-200">
                            {loading ? (
                                <tr><td colSpan="5" className="px-6 py-10 text-center text-gray-500">Loading users...</td></tr>
                            ) : filteredUsers.length === 0 ? (
                                <tr><td colSpan="5" className="px-6 py-10 text-center text-gray-500">No users found.</td></tr>
                            ) : (
                                filteredUsers.map((user) => (
                                    <tr key={user._id} className={`hover:bg-gray-50 transition-colors ${user.isBlocked ? 'opacity-50 bg-red-50' : ''}`}>
                                        <td className="px-6 py-4 whitespace-nowrap">
                                            <div className="flex items-center">
                                                <div className="flex-shrink-0 h-10 w-10">
                                                    <div className="h-10 w-10 rounded-full bg-gradient-to-r from-orange-400 to-red-500 flex justify-center items-center text-white font-bold text-lg">
                                                        {user.name.charAt(0).toUpperCase()}
                                                    </div>
                                                </div>
                                                <div className="ml-4">
                                                    <div className="text-sm font-bold text-gray-900">{user.name} {user.isBlocked && '(Blocked)'}</div>
                                                    <div className={`text-xs ${user.googleId ? 'text-blue-600' : 'text-gray-500'}`}>
                                                        {user.googleId ? 'Google User' : 'Email User'}
                                                    </div>
                                                </div>
                                            </div>
                                        </td>
                                        <td className="px-6 py-4 whitespace-nowrap">
                                            <div className="text-sm text-gray-900">{user.email}</div>
                                            <div className="text-xs text-gray-500">{user.phone || 'No phone'}</div>
                                        </td>
                                        <td className="px-6 py-4 whitespace-nowrap">
                                            <span className={`px-2 inline-flex text-xs leading-5 font-semibold rounded-full ${user.role === 'admin' ? 'bg-purple-100 text-purple-800' : 'bg-green-100 text-green-800'}`}>
                                                {user.role}
                                            </span>
                                        </td>
                                        <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-500">
                                            {new Date(user.createdAt).toLocaleDateString()}
                                        </td>
                                        <td className="px-6 py-4 whitespace-nowrap text-right text-sm font-medium">
                                            <div className="flex justify-end gap-2">
                                                <button
                                                    onClick={() => toggleRole(user)}
                                                    title={user.role === 'admin' ? 'Revoke Admin' : 'Make Admin'}
                                                    className={`p-2 rounded-lg transition-colors ${user.role === 'admin' ? 'text-purple-600 hover:bg-purple-50' : 'text-gray-400 hover:text-purple-600 hover:bg-purple-50'}`}
                                                >
                                                    <ShieldCheckIcon className="h-5 w-5" />
                                                </button>
                                                <button
                                                    onClick={() => toggleBlock(user)}
                                                    title={user.isBlocked ? 'Unblock' : 'Block'}
                                                    className={`p-2 rounded-lg transition-colors ${user.isBlocked ? 'text-red-600 bg-red-50' : 'text-gray-400 hover:text-red-600 hover:bg-red-50'}`}
                                                >
                                                    <NoSymbolIcon className="h-5 w-5" />
                                                </button>
                                                <button
                                                    onClick={() => handleDelete(user._id)}
                                                    title="Delete"
                                                    className="p-2 text-gray-400 hover:text-red-600 hover:bg-red-50 rounded-lg transition-colors"
                                                >
                                                    <TrashIcon className="h-5 w-5" />
                                                </button>
                                            </div>
                                        </td>
                                    </tr>
                                ))
                            )}
                        </tbody>
                    </table>
                </div>
            </div>
        </div>
    );
}
